INSERT INTO hexagrams (id, name, palace, vietnamese_meaning, overall_meaning, career_meaning, love_meaning, wealth_meaning, health_meaning) VALUES (0, 'Bát Thuần Khôn', 'Khôn', 'Bát Thuần Khôn', 'Thuần Khôn: Tượng trưng cho Đất, sự nhu thuận, bao dung, tĩnh lặng để sinh trưởng tốt.', 'Thuần Khôn: Tượng trưng cho Đất, sự nhu thuận, bao dung, tĩnh lặng để sinh trưởng tốt.', 'Thuần Khôn: Tượng trưng cho Đất, sự nhu thuận, bao dung, tĩnh lặng để sinh trưởng tốt.', 'Thuần Khôn: Tượng trưng cho Đất, sự nhu thuận, bao dung, tĩnh lặng để sinh trưởng tốt.', 'Thuần Khôn: Tượng trưng cho Đất, sự nhu thuận, bao dung, tĩnh lặng để sinh trưởng tốt.') ON CONFLICT (id) DO UPDATE SET overall_meaning = EXCLUDED.overall_meaning;
INSERT INTO lines (hexagram_id, line_number, relation, meaning_static, meaning_active) VALUES (0, 1, '', '(Đạ p lên sươ ng thì biế t bă ng dày sắpđế n)', 'Phả i thậ n trọ ng từ bướcđầ u. Tích lũyđiề u tố t từ đầ u.') ON CONFLICT (hexagram_id, line_number) DO UPDATE SET meaning_static = EXCLUDED.meaning_static, meaning_active = EXCLUDED.meaning_active;
INSERT INTO lines (hexagram_id, line_number, relation, meaning_static, meaning_active) VALUES (0, 2, '', '(Thẳ ng, vuông, lớ n thì chẳ ng họ c tậ p cũ ng không có gì bấ t lợ i)', 'Cứ xuôi mà thành.') ON CONFLICT (hexagram_id, line_number) DO UPDATE SET meaning_static = EXCLUDED.meaning_static, meaning_active = EXCLUDED.meaning_active;
INSERT INTO lines (hexagram_id, line_number, relation, meaning_static, meaning_active) VALUES (0, 3, '', '(Theođuổ i việ c nhà vua, không cậ y công thìđượ c tố t lành về sau)', 'Ngậ m kín cái vă n vẻtốtđẹ p củ a ta.') ON CONFLICT (hexagram_id, line_number) DO UPDATE SET meaning_static = EXCLUDED.meaning_static, meaning_active = EXCLUDED.meaning_active;
INSERT INTO lines (hexagram_id, line_number, relation, meaning_static, meaning_active) VALUES (0, 4, '', '(Thắ t túi, không lỗ i, không khen)', 'Giấ u kín cái khôn củ a mìnhđể khỏ i bịám hạ i.Đã giấ u kín thì không có tiế ng khen.') ON CONFLICT (hexagram_id, line_number) DO UPDATE SET meaning_static = EXCLUDED.meaning_static, meaning_active = EXCLUDED.meaning_active;
INSERT INTO lines (hexagram_id, line_number, relation, meaning_static, meaning_active) VALUES (0, 5, '', 'Hào vị thứ 5 đại biểu cho diễn biến tự nhiên, cần xem xét sự sinh khắc của Dụng thần để định đoán cát hung.', 'Hào vị thứ 5 đại biểu cho diễn biến tự nhiên, cần xem xét sự sinh khắc của Dụng thần để định đoán cát hung.') ON CONFLICT (hexagram_id, line_number) DO UPDATE SET meaning_static = EXCLUDED.meaning_static, meaning_active = EXCLUDED.meaning_active;
INSERT INTO lines (hexagram_id, line_number, relation, meaning_static, meaning_active) VALUES (0, 6, '', '(Rồngđánh nhauở đồ ng, máu nó xanh vàng)', 'Thị nh quá gây ra tranh giành, tổ n thươ ng.') ON CONFLICT (hexagram_id, line_number) DO UPDATE SET meaning_static = EXCLUDED.meaning_static, meaning_active = EXCLUDED.meaning_active;
INSERT INTO hexagrams (id, name, palace, vietnamese_meaning, overall_meaning, career_meaning, love_meaning, wealth_meaning, health_meaning) VALUES (1, 'Địa Sơn Khiêm', 'Chưa rõ', 'Địa Sơn Khiêm', 'Khiêm nhường, đức cao đạo trọng, mưu sự được người nâng đỡ thành công.', 'Khiêm nhường, đức cao đạo trọng, mưu sự được người nâng đỡ thành công.', 'Khiêm nhường, đức cao đạo trọng, mưu sự được người nâng đỡ thành công.', 'Khiêm nhường, đức cao đạo trọng, mưu sự được người nâng đỡ thành công.', 'Khiêm nhường, đức cao đạo trọng, mưu sự được người nâng đỡ thành công.') ON CONFLICT (id) DO UPDATE SET overall_meaning = EXCLUDED.overall_meaning;
INSERT INTO lines (hexagram_id, line_number, relation, meaning_static, meaning_active) VALUES (1, 1, '', 'c lòng ngườ i trên mà thi hành chính đạ o. Gầ n vua tố t thìđượ c lợ i. Tiể u nhân hiể u biế t nông cạ n không hiểuđượ c quân tử.', 'c lòng ngườ i trên mà thi hành chính đạ o. Gầ n vua tố t thìđượ c lợ i. Tiể u nhân hiể u biế t nông cạ n không hiểuđượ c quân tử.') ON CONFLICT (hexagram_id, line_number) DO UPDATE SET meaning_static = EXCLUDED.meaning_static, meaning_active = EXCLUDED.meaning_active;
INSERT INTO lines (hexagram_id, line_number, relation, meaning_static, meaning_active) VALUES (1, 2, '', 'Cùng nhau tớ i, không có gì là không lợ i. Lấ y sứ c người giúp mệ nh trờ i, chứ không nên ngồ i yên mà chờmệ nh trờ i. Xem bằ ng cách dòm ngó thì không rõ. Tuy vậ y mà thuậ n theo là con gái tố t.', 'Cùng nhau tớ i, không có gì là không lợ i. Lấ y sứ c người giúp mệ nh trờ i, chứ không nên ngồ i yên mà chờmệ nh trờ i. Xem bằ ng cách dòm ngó thì không rõ. Tuy vậ y mà thuậ n theo là con gái tố t.') ON CONFLICT (hexagram_id, line_number) DO UPDATE SET meaning_static = EXCLUDED.meaning_static, meaning_active = EXCLUDED.meaning_active;
INSERT INTO lines (hexagram_id, line_number, relation, meaning_static, meaning_active) VALUES (1, 3, '', 't ngào, dua nị nh mà tớ i thì không có lợ i. Tự xét bả n thân, nếuđố i phóđượ c hoàn cả nh thì tiế n lên, không thì thôi.', 't ngào, dua nị nh mà tớ i thì không có lợ i. Tự xét bả n thân, nếuđố i phóđượ c hoàn cả nh thì tiế n lên, không thì thôi.') ON CONFLICT (hexagram_id, line_number) DO UPDATE SET meaning_static = EXCLUDED.meaning_static, meaning_active = EXCLUDED.meaning_active;
INSERT INTO lines (hexagram_id, line_number, relation, meaning_static, meaning_active) VALUES (1, 4, '', 'n vua, dùng ngườ i hiềnđểcầ u thân kẻdướ i, cho nên không lỗ i. Vua tố t và tín nhiệ m mình thì hãyđ em tài ra giúp.', 'n vua, dùng ngườ i hiềnđểcầ u thân kẻdướ i, cho nên không lỗ i. Vua tố t và tín nhiệ m mình thì hãyđ em tài ra giúp.') ON CONFLICT (hexagram_id, line_number) DO UPDATE SET meaning_static = EXCLUDED.meaning_static, meaning_active = EXCLUDED.meaning_active;
INSERT INTO lines (hexagram_id, line_number, relation, meaning_static, meaning_active) VALUES (1, 5, '', 'Vua tuy ít tài như ng biế t chọ n ngườ i hiề n tài, nhưvậ y làtố t. Xem dân cho biế t sự tình. "Thượ ng bấ t chánh, hạtắ c loạ n".', 'Vua tuy ít tài như ng biế t chọ n ngườ i hiề n tài, nhưvậ y làtố t. Xem dân cho biế t sự tình. "Thượ ng bấ t chánh, hạtắ c loạ n".') ON CONFLICT (hexagram_id, line_number) DO UPDATE SET meaning_static = EXCLUDED.meaning_static, meaning_active = EXCLUDED.meaning_active;
INSERT INTO lines (hexagram_id, line_number, relation, meaning_static, meaning_active) VALUES (1, 6, '', 'y lòngđôn hậ u mà gầ n gũ i vớ i mọ i ngườ i, tố t. Tuy khôngở ngôi như ng khôngđượ c phóng túng theo ý riêng vì bị dânđểý.', 'y lòngđôn hậ u mà gầ n gũ i vớ i mọ i ngườ i, tố t. Tuy khôngở ngôi như ng khôngđượ c phóng túng theo ý riêng vì bị dânđểý.') ON CONFLICT (hexagram_id, line_number) DO UPDATE SET meaning_static = EXCLUDED.meaning_static, meaning_active = EXCLUDED.meaning_active;
INSERT INTO hexagrams (id, name, palace, vietnamese_meaning, overall_meaning, career_meaning, love_meaning, wealth_meaning, health_meaning) VALUES (2, 'Địa Thủy Sư', 'Khảm', 'Địa Thủy Sư', 'Ra quân, tập hợp lực lượng, cần kỷ luật sắt và tướng lĩnh tài ba.', 'Ra quân, tập hợp lực lượng, cần kỷ luật sắt và tướng lĩnh tài ba.', 'Ra quân, tập hợp lực lượng, cần kỷ luật sắt và tướng lĩnh tài ba.', 'Ra quân, tập hợp lực lượng, cần kỷ luật sắt và tướng lĩnh tài ba.', 'Ra quân, tập hợp lực lượng, cần kỷ luật sắt và tướng lĩnh tài ba.') ON CONFLICT (id) DO UPDATE SET overall_meaning = EXCLUDED.overall_meaning;
INSERT INTO lines (hexagram_id, line_number, relation, meaning_static, meaning_active) VALUES (2, 1, '', 'u củ a việ c ra quân, phả i chú trọngđế n kỷ luậ t.Nế u không khéođểmấ t lòng quân sĩ , xấ u. Trong lòng không tin, mà muố n thân vớ i ngườ i ta, thì ngườ i ta ai thân vớ i mình?', 'u củ a việ c ra quân, phả i chú trọngđế n kỷ luậ t.Nế u không khéođểmấ t lòng quân sĩ , xấ u. Trong lòng không tin, mà muố n thân vớ i ngườ i ta, thì ngườ i ta ai thân vớ i mình?') ON CONFLICT (hexagram_id, line_number) DO UPDATE SET meaning_static = EXCLUDED.meaning_static, meaning_active = EXCLUDED.meaning_active;
INSERT INTO lines (hexagram_id, line_number, relation, meaning_static, meaning_active) VALUES (2, 2, '', 'o làm tôi không dám chuyên chếmộ t việ c gì, nhưng việ c quân ngoài mặ t trậnđượ c quyề n chuyên chế. Cái quyề n chọ n tài mà dùng tuyởng ườ i trên, mà sự đ em thân cho nướ c,ắ t doở mình. Giữ đạ o trung chínhđểchờng ườ i trênđế n tìm và giữ đượ c phẩ m giá củ a mình.', 'o làm tôi không dám chuyên chếmộ t việ c gì, nhưng việ c quân ngoài mặ t trậnđượ c quyề n chuyên chế. Cái quyề n chọ n tài mà dùng tuyởng ườ i trên, mà sự đ em thân cho nướ c,ắ t doở mình. Giữ đạ o trung chínhđểchờng ườ i trênđế n tìm và giữ đượ c phẩ m giá củ a mình.') ON CONFLICT (hexagram_id, line_number) DO UPDATE SET meaning_static = EXCLUDED.meaning_static, meaning_active = EXCLUDED.meaning_active;
INSERT INTO lines (hexagram_id, line_number, relation, meaning_static, meaning_active) VALUES (2, 3, '', 'thua thiệtđế n phả i khiêng thây mà về . Nươ ng tự a, giao phó cho hai ba ng ườ i, sao thành công đượ c. Gầ n liề n vớ i kẻ khôngđáng gầ n thì hố i hậ n cũ ng muộ n rồ i. 3', 'thua thiệtđế n phả i khiêng thây mà về . Nươ ng tự a, giao phó cho hai ba ng ườ i, sao thành công đượ c. Gầ n liề n vớ i kẻ khôngđáng gầ n thì hố i hậ n cũ ng muộ n rồ i. 3') ON CONFLICT (hexagram_id, line_number) DO UPDATE SET meaning_static = EXCLUDED.meaning_static, meaning_active = EXCLUDED.meaning_active;
INSERT INTO lines (hexagram_id, line_number, relation, meaning_static, meaning_active) VALUES (2, 4, '', 'Giữlấ y toàn quân mà lui. Biế t khó mà lui,đó là sự thường trong việ c quân. Bên ngoài gầ n liề n vớ i ngườ i hiề n,để mà theo ngườ i trên vậ y.', 'Giữlấ y toàn quân mà lui. Biế t khó mà lui,đó là sự thường trong việ c quân. Bên ngoài gầ n liề n vớ i ngườ i hiề n,để mà theo ngườ i trên vậ y.') ON CONFLICT (hexagram_id, line_number) DO UPDATE SET meaning_static = EXCLUDED.meaning_static, meaning_active = EXCLUDED.meaning_active;
INSERT INTO lines (hexagram_id, line_number, relation, meaning_static, meaning_active) VALUES (2, 5, '', 'Quân giặ c tràn lấnđế n mình, chẳ ng nhịnđượ c mà phảiứngđị ch. Nế u sai quân tử làm việ c màđể tiể u nhân xen vào là sai chúng khiêng thây mà về. Như khi să n thú, vua chỉ vây có ba mặ t (còn mộ t mặ t bỏ ngõ) cho cầ m thú thoát ra phíađ ó. Ngườ i xung quanhđượ c cả m hóa, không phả i rănđ e. Ai phụ c tùng thì cứtớ i.', 'Quân giặ c tràn lấnđế n mình, chẳ ng nhịnđượ c mà phảiứngđị ch. Nế u sai quân tử làm việ c màđể tiể u nhân xen vào là sai chúng khiêng thây mà về. Như khi să n thú, vua chỉ vây có ba mặ t (còn mộ t mặ t bỏ ngõ) cho cầ m thú thoát ra phíađ ó. Ngườ i xung quanhđượ c cả m hóa, không phả i rănđ e. Ai phụ c tùng thì cứtớ i.') ON CONFLICT (hexagram_id, line_number) DO UPDATE SET meaning_static = EXCLUDED.meaning_static, meaning_active = EXCLUDED.meaning_active;
INSERT INTO lines (hexagram_id, line_number, relation, meaning_static, meaning_active) VALUES (2, 6, '', 'Việ c quânđã xong rồ i tứ c là lúc luậ n công ban thưở ng. Kẻ tiể u nhân dù là có công cũ ng không nênđể chúngđượ c cótướcđấ t. Chỉ ưuđãi chúng bằ ng vàng bạ c. Lúcđầ u gầ n liề n vớ i nhau không theo đạ o nghĩ a,để sinh hiềm khích về sau, thiên hạnhư thếcũ ng nhiề u. Trongđạ o gầ n liềnvớ i ngườ i, trướ c thiệ n mà sau cũ ng thiệ n.', 'Việ c quânđã xong rồ i tứ c là lúc luậ n công ban thưở ng. Kẻ tiể u nhân dù là có công cũ ng không nênđể chúngđượ c cótướcđấ t. Chỉ ưuđãi chúng bằ ng vàng bạ c. Lúcđầ u gầ n liề n vớ i nhau không theo đạ o nghĩ a,để sinh hiềm khích về sau, thiên hạnhư thếcũ ng nhiề u. Trongđạ o gầ n liềnvớ i ngườ i, trướ c thiệ n mà sau cũ ng thiệ n.') ON CONFLICT (hexagram_id, line_number) DO UPDATE SET meaning_static = EXCLUDED.meaning_static, meaning_active = EXCLUDED.meaning_active;
