INSERT INTO hexagrams (id, name, palace, vietnamese_meaning, overall_meaning, career_meaning, love_meaning, wealth_meaning, health_meaning) VALUES (6, 'Địa Trạch Lâm', 'Khôn', 'Địa Trạch Lâm', 'Đến gần, giám sát thúc đẩy, cơ hội lớn đang cận kề hành động.', 'Đến gần, giám sát thúc đẩy, cơ hội lớn đang cận kề hành động.', 'Đến gần, giám sát thúc đẩy, cơ hội lớn đang cận kề hành động.', 'Đến gần, giám sát thúc đẩy, cơ hội lớn đang cận kề hành động.', 'Đến gần, giám sát thúc đẩy, cơ hội lớn đang cận kề hành động.') ON CONFLICT (id) DO UPDATE SET overall_meaning = EXCLUDED.overall_meaning;
INSERT INTO lines (hexagram_id, line_number, relation, meaning_static, meaning_active) VALUES (6, 1, '', 'Thèm thuồ ng cầuă n vớ i ngườ i khácđể nuôi xác thị t, quên phầ n tinh thầ n củ a mình. Mê muộ i vì ham muố n,vậ y làxấ u. Kẻ quá sợ hãi cẩ n thậ n mà không có lỗ i.', 'Thèm thuồ ng cầuă n vớ i ngườ i khácđể nuôi xác thị t, quên phầ n tinh thầ n củ a mình. Mê muộ i vì ham muố n,vậ y làxấ u. Kẻ quá sợ hãi cẩ n thậ n mà không có lỗ i.') ON CONFLICT (hexagram_id, line_number) DO UPDATE SET meaning_static = EXCLUDED.meaning_static, meaning_active = EXCLUDED.meaning_active;
INSERT INTO lines (hexagram_id, line_number, relation, meaning_static, meaning_active) VALUES (6, 2, '', 'ng lẽngườ i trên xină n kẻdướ i. Nhưvậ y sẽbịtừchố i,bịnhụ c. Chồ ng gìa lấyđượ c vợ trẻ . Mộ t ngườ i qúa cứ ng mà biế t dùngkẻmề m giúp mình nên làm đượ c công cả quá.', 'ng lẽngườ i trên xină n kẻdướ i. Nhưvậ y sẽbịtừchố i,bịnhụ c. Chồ ng gìa lấyđượ c vợ trẻ . Mộ t ngườ i qúa cứ ng mà biế t dùngkẻmề m giúp mình nên làm đượ c công cả quá.') ON CONFLICT (hexagram_id, line_number) DO UPDATE SET meaning_static = EXCLUDED.meaning_static, meaning_active = EXCLUDED.meaning_active;
INSERT INTO lines (hexagram_id, line_number, relation, meaning_static, meaning_active) VALUES (6, 3, '', 'Không chị u ngồ i yên, thấyđâu cóă n làđâm vào, rấ t xấ u. Kẻcươ ng cườ ng quá không thể theo ngườ i, ngườ i cũ ng khônggầ n gũ i giúpđỡ mình, nhưcộ t nhà không thểchống đỡ.', 'Không chị u ngồ i yên, thấyđâu cóă n làđâm vào, rấ t xấ u. Kẻcươ ng cườ ng quá không thể theo ngườ i, ngườ i cũ ng khônggầ n gũ i giúpđỡ mình, nhưcộ t nhà không thểchống đỡ.') ON CONFLICT (hexagram_id, line_number) DO UPDATE SET meaning_static = EXCLUDED.meaning_static, meaning_active = EXCLUDED.meaning_active;
INSERT INTO lines (hexagram_id, line_number, relation, meaning_static, meaning_active) VALUES (6, 4, '', 'Biế t hạ mình cầ u ngườ i dướ i nuôi mình, tuy là trái lẽ thườ ng, như ng là vì ngườ i tố t vì muố n lậ p sự nghiệ p và sausẽ giúpđỡ dân chúng nên vẫn đượ c tố t. Nhằ m ngôi gầ n vua, là kẻ gánh trách nhiệ m cả quá, nế u không phả i là bậ c cươ ng trung thì không gánh nỗ i trách nhiệ m.', 'Biế t hạ mình cầ u ngườ i dướ i nuôi mình, tuy là trái lẽ thườ ng, như ng là vì ngườ i tố t vì muố n lậ p sự nghiệ p và sausẽ giúpđỡ dân chúng nên vẫn đượ c tố t. Nhằ m ngôi gầ n vua, là kẻ gánh trách nhiệ m cả quá, nế u không phả i là bậ c cươ ng trung thì không gánh nỗ i trách nhiệ m.') ON CONFLICT (hexagram_id, line_number) DO UPDATE SET meaning_static = EXCLUDED.meaning_static, meaning_active = EXCLUDED.meaning_active;
INSERT INTO lines (hexagram_id, line_number, relation, meaning_static, meaning_active) VALUES (6, 5, '', 't ông vua kém tài nên phả i nhờngườ i khác giúp mình, vì tài hèn kém nên không thể làmđượ c chuyệ n lớ n. Vợ già lấ y chồ ng tráng kiệ n, dầ u không tộ i lỗ i như ng chẳng phảiđẹpđôi.', 't ông vua kém tài nên phả i nhờngườ i khác giúp mình, vì tài hèn kém nên không thể làmđượ c chuyệ n lớ n. Vợ già lấ y chồ ng tráng kiệ n, dầ u không tộ i lỗ i như ng chẳng phảiđẹpđôi.') ON CONFLICT (hexagram_id, line_number) DO UPDATE SET meaning_static = EXCLUDED.meaning_static, meaning_active = EXCLUDED.meaning_active;
INSERT INTO lines (hexagram_id, line_number, relation, meaning_static, meaning_active) VALUES (6, 6, '', 'Vì tài củ a vua khôngđủ nên phả i nươ ng tự a vào mình thì mình nênđ em hế t tài lựcđể gánh vác giúpđỡmọ i ngườ i. Ởchỗ quá cự c, tài hèn không thể làm nên công việ c. Quá lội màđế n chếtđuố i, là do tự mình làm ra, không thể đổlỗ i cho ai.', 'Vì tài củ a vua khôngđủ nên phả i nươ ng tự a vào mình thì mình nênđ em hế t tài lựcđể gánh vác giúpđỡmọ i ngườ i. Ởchỗ quá cự c, tài hèn không thể làm nên công việ c. Quá lội màđế n chếtđuố i, là do tự mình làm ra, không thể đổlỗ i cho ai.') ON CONFLICT (hexagram_id, line_number) DO UPDATE SET meaning_static = EXCLUDED.meaning_static, meaning_active = EXCLUDED.meaning_active;
INSERT INTO hexagrams (id, name, palace, vietnamese_meaning, overall_meaning, career_meaning, love_meaning, wealth_meaning, health_meaning) VALUES (7, 'Địa Thiên Thái', 'Khôn', 'Địa Thiên Thái', 'Thái bình, giao hòa tốt đẹp, trong ngoài thuận lợi, hanh thông cát tường.', 'Thái bình, giao hòa tốt đẹp, trong ngoài thuận lợi, hanh thông cát tường.', 'Thái bình, giao hòa tốt đẹp, trong ngoài thuận lợi, hanh thông cát tường.', 'Thái bình, giao hòa tốt đẹp, trong ngoài thuận lợi, hanh thông cát tường.', 'Thái bình, giao hòa tốt đẹp, trong ngoài thuận lợi, hanh thông cát tường.') ON CONFLICT (id) DO UPDATE SET overall_meaning = EXCLUDED.overall_meaning;
INSERT INTO lines (hexagram_id, line_number, relation, meaning_static, meaning_active) VALUES (7, 1, '', 'i quân tử tiế n lênắ t cùng bè phái dắ t díu nhau thực hành cáiđạ o củ a mình. Chư a có ngườ i nào có thể đứng riêng mộ t mình. Bọ n tiể u nhân kế t bè tiế n lên, cho nên ră n họnế u chính bề n thìđượ c tố t lành, nghĩ a là có thểnhư thế thì họsẽ biế n thành quântử.', 'i quân tử tiế n lênắ t cùng bè phái dắ t díu nhau thực hành cáiđạ o củ a mình. Chư a có ngườ i nào có thể đứng riêng mộ t mình. Bọ n tiể u nhân kế t bè tiế n lên, cho nên ră n họnế u chính bề n thìđượ c tố t lành, nghĩ a là có thểnhư thế thì họsẽ biế n thành quântử.') ON CONFLICT (hexagram_id, line_number) DO UPDATE SET meaning_static = EXCLUDED.meaning_static, meaning_active = EXCLUDED.meaning_active;
INSERT INTO lines (hexagram_id, line_number, relation, meaning_static, meaning_active) VALUES (7, 2, '', 'Trongđờ i thái bình, th ườ ng hay thủ thườ ng, sợ thayđổ i,nế u không có hă ng hái củ a kẻ tay không lộ i sông, thì không thể nào làm việ c. Kẻ tiể u nhân mà biế t bao dong, vâng thuận đấ ng quân tử,ấ y là cách tố t củ a tiể u nhân.Đấngđạ i nhân há chị u uố n mình, vâng thuậ n ngườ i trên.', 'Trongđờ i thái bình, th ườ ng hay thủ thườ ng, sợ thayđổ i,nế u không có hă ng hái củ a kẻ tay không lộ i sông, thì không thể nào làm việ c. Kẻ tiể u nhân mà biế t bao dong, vâng thuận đấ ng quân tử,ấ y là cách tố t củ a tiể u nhân.Đấngđạ i nhân há chị u uố n mình, vâng thuậ n ngườ i trên.') ON CONFLICT (hexagram_id, line_number) DO UPDATE SET meaning_static = EXCLUDED.meaning_static, meaning_active = EXCLUDED.meaning_active;
INSERT INTO lines (hexagram_id, line_number, relation, meaning_static, meaning_active) VALUES (7, 3, '', 'Không cái gì yên phẳ ng mãi mà không lồ i lõm.Đã cực thị nh rồ i thì sắ p gian nan.Hễ mà có thể giữ đượ c tấ m lòng khó nhọ c thì không cầ n lo vậ n trờiắtđế n. Kẻ tiể u nhân có chí muố n làm hạ i bậ c thiệ n nhân mà chư a làmđượ c.', 'Không cái gì yên phẳ ng mãi mà không lồ i lõm.Đã cực thị nh rồ i thì sắ p gian nan.Hễ mà có thể giữ đượ c tấ m lòng khó nhọ c thì không cầ n lo vậ n trờiắtđế n. Kẻ tiể u nhân có chí muố n làm hạ i bậ c thiệ n nhân mà chư a làmđượ c.') ON CONFLICT (hexagram_id, line_number) DO UPDATE SET meaning_static = EXCLUDED.meaning_static, meaning_active = EXCLUDED.meaning_active;
INSERT INTO lines (hexagram_id, line_number, relation, meaning_static, meaning_active) VALUES (7, 4, '', 'n tiể u nhân kế t hợ p vớ i nhauđể làm hạ i chínhđạ o.Đấ ng quân tử phả i nên ră n lo. Biế t ră n lo thì có thể giữ. Kẻ có tài làm qua cuộ c bỉ màđượ c ngôi cao,đủ để giúpđỡ ngườ i trên, vượ t khỏ i cuộ c bĩ . Gặ p lúc vuađươ ng bĩ mà cậ y có công thì chỉrướ c lấ y sự ghen ghét mà thôi. Làm việ c gì cũng nên theo mênh lệ nh củ a ngườ i trên.', 'n tiể u nhân kế t hợ p vớ i nhauđể làm hạ i chínhđạ o.Đấ ng quân tử phả i nên ră n lo. Biế t ră n lo thì có thể giữ. Kẻ có tài làm qua cuộ c bỉ màđượ c ngôi cao,đủ để giúpđỡ ngườ i trên, vượ t khỏ i cuộ c bĩ . Gặ p lúc vuađươ ng bĩ mà cậ y có công thì chỉrướ c lấ y sự ghen ghét mà thôi. Làm việ c gì cũng nên theo mênh lệ nh củ a ngườ i trên.') ON CONFLICT (hexagram_id, line_number) DO UPDATE SET meaning_static = EXCLUDED.meaning_static, meaning_active = EXCLUDED.meaning_active;
INSERT INTO lines (hexagram_id, line_number, relation, meaning_static, meaning_active) VALUES (7, 5, '', 'Em gái vua chị u làm vợmộ t ngườ i hiề n trong giớ i bình dân, sẽ đượ c hưở ng phúc. Đấngđạ i nhânđượ c chính vị nên có thể làm tắ t cuộ c bĩ trong thiên hạ . Như ng vì cuộ c bĩchư a qua nên phả i tựră n mình.', 'Em gái vua chị u làm vợmộ t ngườ i hiề n trong giớ i bình dân, sẽ đượ c hưở ng phúc. Đấngđạ i nhânđượ c chính vị nên có thể làm tắ t cuộ c bĩ trong thiên hạ . Như ng vì cuộ c bĩchư a qua nên phả i tựră n mình.') ON CONFLICT (hexagram_id, line_number) DO UPDATE SET meaning_static = EXCLUDED.meaning_static, meaning_active = EXCLUDED.meaning_active;
INSERT INTO lines (hexagram_id, line_number, relation, meaning_static, meaning_active) VALUES (7, 6, '', 'Cuộ c thái sắ p hế t, tình củ a kẻ trên ngườ i dướ i không thông nhau, dùng họ thì loạ n. Có ban lệ nh cũ ng không ai nghe. Cái việ c chuyể n nguy thành an, nế u không có tài thì sẽ không làm nỗ i. Bĩ nghiêng thì là thái rồ i.', 'Cuộ c thái sắ p hế t, tình củ a kẻ trên ngườ i dướ i không thông nhau, dùng họ thì loạ n. Có ban lệ nh cũ ng không ai nghe. Cái việ c chuyể n nguy thành an, nế u không có tài thì sẽ không làm nỗ i. Bĩ nghiêng thì là thái rồ i.') ON CONFLICT (hexagram_id, line_number) DO UPDATE SET meaning_static = EXCLUDED.meaning_static, meaning_active = EXCLUDED.meaning_active;
INSERT INTO hexagrams (id, name, palace, vietnamese_meaning, overall_meaning, career_meaning, love_meaning, wealth_meaning, health_meaning) VALUES (8, 'Sơn Địa Bác', 'Càn', 'Sơn Địa Bác', 'Bóc lột, hao mòn, tiểu nhân lấn át quân tử, nên tĩnh lặng tự thủ.', 'Bóc lột, hao mòn, tiểu nhân lấn át quân tử, nên tĩnh lặng tự thủ.', 'Bóc lột, hao mòn, tiểu nhân lấn át quân tử, nên tĩnh lặng tự thủ.', 'Bóc lột, hao mòn, tiểu nhân lấn át quân tử, nên tĩnh lặng tự thủ.', 'Bóc lột, hao mòn, tiểu nhân lấn át quân tử, nên tĩnh lặng tự thủ.') ON CONFLICT (id) DO UPDATE SET overall_meaning = EXCLUDED.overall_meaning;
INSERT INTO lines (hexagram_id, line_number, relation, meaning_static, meaning_active) VALUES (8, 1, '', 'u ngườ i trên chư a tin, thì yên phậ n tự thủ. Dù mố i hạ i chư a rõ rệ t, quân tử có thể thấyđượ c cho nên mớiđi để tránh.', 'u ngườ i trên chư a tin, thì yên phậ n tự thủ. Dù mố i hạ i chư a rõ rệ t, quân tử có thể thấyđượ c cho nên mớiđi để tránh.') ON CONFLICT (hexagram_id, line_number) DO UPDATE SET meaning_static = EXCLUDED.meaning_static, meaning_active = EXCLUDED.meaning_active;
INSERT INTO lines (hexagram_id, line_number, relation, meaning_static, meaning_active) VALUES (8, 2, '', 'Tuyở trên không cóứ ng việ n như ng lâu rồiắ t rõ, người trên phả i tự nhiên tìm nó và banơ n lộ c cho nó. Đấ ng quân tửbịkẻâm tố i làm hạ i như ng mà có cách tựxử , cho nênđượ c khỏ i mau chóng.', 'Tuyở trên không cóứ ng việ n như ng lâu rồiắ t rõ, người trên phả i tự nhiên tìm nó và banơ n lộ c cho nó. Đấ ng quân tửbịkẻâm tố i làm hạ i như ng mà có cách tựxử , cho nênđượ c khỏ i mau chóng.') ON CONFLICT (hexagram_id, line_number) DO UPDATE SET meaning_static = EXCLUDED.meaning_static, meaning_active = EXCLUDED.meaning_active;
INSERT INTO lines (hexagram_id, line_number, relation, meaning_static, meaning_active) VALUES (8, 3, '', 'Thuậ n vớ i bề trên, cùng chí vớ i mọ i ngườ i, mọ i ngườ i tin theo, tố t. Không thể kíp chính, giế t kẻ đầ u ác và bài trừhủtụ c thì phải làm dầ n dầ n.', 'Thuậ n vớ i bề trên, cùng chí vớ i mọ i ngườ i, mọ i ngườ i tin theo, tố t. Không thể kíp chính, giế t kẻ đầ u ác và bài trừhủtụ c thì phải làm dầ n dầ n.') ON CONFLICT (hexagram_id, line_number) DO UPDATE SET meaning_static = EXCLUDED.meaning_static, meaning_active = EXCLUDED.meaning_active;
INSERT INTO lines (hexagram_id, line_number, relation, meaning_static, meaning_active) VALUES (8, 4, '', 'Dùng cách bấ t chínhđể kiế m ngôi caođó là nguy. Kẻ gian tàđượ c lòng tin củ a vua là do cướp đượ c lòng họ . Biết che bớ t sự sáng củ a mình.', 'Dùng cách bấ t chínhđể kiế m ngôi caođó là nguy. Kẻ gian tàđượ c lòng tin củ a vua là do cướp đượ c lòng họ . Biết che bớ t sự sáng củ a mình.') ON CONFLICT (hexagram_id, line_number) DO UPDATE SET meaning_static = EXCLUDED.meaning_static, meaning_active = EXCLUDED.meaning_active;
INSERT INTO lines (hexagram_id, line_number, relation, meaning_static, meaning_active) VALUES (8, 5, '', 'n theo, nênđ em lòng thành thự c tin dùng thì tố t. Gỉ a cáchđ iênđể khỏ i bịhạ i. Tuy gặ p hoạ n nạ n mà sự sáng vẫn còn.', 'n theo, nênđ em lòng thành thự c tin dùng thì tố t. Gỉ a cáchđ iênđể khỏ i bịhạ i. Tuy gặ p hoạ n nạ n mà sự sáng vẫn còn.') ON CONFLICT (hexagram_id, line_number) DO UPDATE SET meaning_static = EXCLUDED.meaning_static, meaning_active = EXCLUDED.meaning_active;
INSERT INTO lines (hexagram_id, line_number, relation, meaning_static, meaning_active) VALUES (8, 6, '', 'Tiếnđế n cùng tộ t thì sẽhỏ ng vềsự nóng kíp Giế t gà mà dùngđế n dao mổ trâu thìđáng tiế c. Ởchỗ cao mà sáng, thì nên soi khắ p bố n phươ ng; thế mà bịhại mà tố i tă m. Lúc chótắ t tựhạ i mình, nguy.', 'Tiếnđế n cùng tộ t thì sẽhỏ ng vềsự nóng kíp Giế t gà mà dùngđế n dao mổ trâu thìđáng tiế c. Ởchỗ cao mà sáng, thì nên soi khắ p bố n phươ ng; thế mà bịhại mà tố i tă m. Lúc chótắ t tựhạ i mình, nguy.') ON CONFLICT (hexagram_id, line_number) DO UPDATE SET meaning_static = EXCLUDED.meaning_static, meaning_active = EXCLUDED.meaning_active;
