INSERT INTO lines (hexagram_id, line_number, relation, meaning_static, meaning_active) VALUES (12, 1, '', 'i ta làm việ c,ắ t phả i cân nhắ c việcđó có thể làm rồimớ i quyế t. Đề phòng kẻ tiể u nhân từ lúc banđầ u thì nó không thể làm gì.', 'i ta làm việ c,ắ t phả i cân nhắ c việcđó có thể làm rồimớ i quyế t. Đề phòng kẻ tiể u nhân từ lúc banđầ u thì nó không thể làm gì.') ON CONFLICT (hexagram_id, line_number) DO UPDATE SET meaning_static = EXCLUDED.meaning_static, meaning_active = EXCLUDED.meaning_active;
INSERT INTO lines (hexagram_id, line_number, relation, meaning_static, meaning_active) VALUES (12, 2, '', 'Lúc quân tử quyế t vớ i tiể u nhân, không thể quên sựrănngừ a. Kẻ "gặ p" khôngđượ c lòng thành, tứ c là trái vớiđạ o "gặ p". Khôngđế n phầ n khách', 'Lúc quân tử quyế t vớ i tiể u nhân, không thể quên sựrănngừ a. Kẻ "gặ p" khôngđượ c lòng thành, tứ c là trái vớiđạ o "gặ p". Khôngđế n phầ n khách') ON CONFLICT (hexagram_id, line_number) DO UPDATE SET meaning_static = EXCLUDED.meaning_static, meaning_active = EXCLUDED.meaning_active;
INSERT INTO lines (hexagram_id, line_number, relation, meaning_static, meaning_active) VALUES (12, 3, '', 'ng lúc quyế t trừkẻ tiể u nhân mà mình lạ i riêng hòa nhau vớ i nó;đủ biế t là trái. Dùng kiể u phi nghĩ a mà cầ u cho gặ p, vẫ n là có lỗ i rồ i. Chậ t vật tiế n lên khó khă n tứ c không thểbỏ ngay.', 'ng lúc quyế t trừkẻ tiể u nhân mà mình lạ i riêng hòa nhau vớ i nó;đủ biế t là trái. Dùng kiể u phi nghĩ a mà cầ u cho gặ p, vẫ n là có lỗ i rồ i. Chậ t vật tiế n lên khó khă n tứ c không thểbỏ ngay.') ON CONFLICT (hexagram_id, line_number) DO UPDATE SET meaning_static = EXCLUDED.meaning_static, meaning_active = EXCLUDED.meaning_active;
INSERT INTO lines (hexagram_id, line_number, relation, meaning_static, meaning_active) VALUES (12, 4, '', 'Nghe lờ i nói phả i mà biế t dùng, chỉ có kẻcươ ng minh mới làmđượ c. Làm ngườ i trên mà bịkẻd ướ i lìa bỏ,ắ t có hung biế n.', 'Nghe lờ i nói phả i mà biế t dùng, chỉ có kẻcươ ng minh mới làmđượ c. Làm ngườ i trên mà bịkẻd ướ i lìa bỏ,ắ t có hung biế n.') ON CONFLICT (hexagram_id, line_number) DO UPDATE SET meaning_static = EXCLUDED.meaning_static, meaning_active = EXCLUDED.meaning_active;
INSERT INTO lines (hexagram_id, line_number, relation, meaning_static, meaning_active) VALUES (12, 5, '', 'u qủ a quyế t mà quyế t vớ i nó, lạ i không làm sự quá dữ. Ngườ i hiềnởchốnẩ n cư , ngườ i trên nên lấyđạ o trung chính mà cầ u ngườ i hiề n.', 'u qủ a quyế t mà quyế t vớ i nó, lạ i không làm sự quá dữ. Ngườ i hiềnởchốnẩ n cư , ngườ i trên nên lấyđạ o trung chính mà cầ u ngườ i hiề n.') ON CONFLICT (hexagram_id, line_number) DO UPDATE SET meaning_static = EXCLUDED.meaning_static, meaning_active = EXCLUDED.meaning_active;
INSERT INTO lines (hexagram_id, line_number, relation, meaning_static, meaning_active) VALUES (12, 6, '', 'i quân tử đượ c thờ i, quyế t trừmộ t kẻ tiể u nhânđã nguycựcđiể m vậ y. Khôngđượ c gặ p kẻ đáng gặ p. Ngườ i ta gặ p nhau thì cầ n hòa thuậnđể tiế p nhau.', 'i quân tử đượ c thờ i, quyế t trừmộ t kẻ tiể u nhânđã nguycựcđiể m vậ y. Khôngđượ c gặ p kẻ đáng gặ p. Ngườ i ta gặ p nhau thì cầ n hòa thuậnđể tiế p nhau.') ON CONFLICT (hexagram_id, line_number) DO UPDATE SET meaning_static = EXCLUDED.meaning_static, meaning_active = EXCLUDED.meaning_active;
