INSERT INTO hexagrams (id, name, palace, vietnamese_meaning, overall_meaning, career_meaning, love_meaning, wealth_meaning, health_meaning) VALUES (18, 'Bát Thuần Khảm', 'Khảm', 'Bát Thuần Khảm', 'Khảm hiểm, khó khăn chồng chất, cần lòng tin chí thành vượt hiểm nguy.', 'Khảm hiểm, khó khăn chồng chất, cần lòng tin chí thành vượt hiểm nguy.', 'Khảm hiểm, khó khăn chồng chất, cần lòng tin chí thành vượt hiểm nguy.', 'Khảm hiểm, khó khăn chồng chất, cần lòng tin chí thành vượt hiểm nguy.', 'Khảm hiểm, khó khăn chồng chất, cần lòng tin chí thành vượt hiểm nguy.') ON CONFLICT (id) DO UPDATE SET overall_meaning = EXCLUDED.overall_meaning;
INSERT INTO lines (hexagram_id, line_number, relation, meaning_static, meaning_active) VALUES (18, 1, '', 'i hả m hiễ m, không thểtự mình vượ t qua,ắtđượcngườ i trên cứ u giúp thì có thểv ượ t qua sự khố n. Công dụ ng củ a giế ng doởnướ c nuôiđượ c ngườ i ta. Ngườ i tađươ ng lúc giúp cho mọ i ngườ i mà tài hèn thì bị đờ i ruồ ng bỏ vậ y.', 'i hả m hiễ m, không thểtự mình vượ t qua,ắtđượcngườ i trên cứ u giúp thì có thểv ượ t qua sự khố n. Công dụ ng củ a giế ng doởnướ c nuôiđượ c ngườ i ta. Ngườ i tađươ ng lúc giúp cho mọ i ngườ i mà tài hèn thì bị đờ i ruồ ng bỏ vậ y.') ON CONFLICT (hexagram_id, line_number) DO UPDATE SET meaning_static = EXCLUDED.meaning_static, meaning_active = EXCLUDED.meaning_active;
INSERT INTO lines (hexagram_id, line_number, relation, meaning_static, meaning_active) VALUES (18, 2, '', 'u màđấ ng quân tửvẫ n muố n là việ c làmơ n cho thiênhạ , khiế n cho thiên hạv ượ t qua cả nh khố n. Cuố i cùngđứccủ a họcũ ng thấ u tai ngườ i trên. Là kẻ có tài, có thể nuôi ngườ i giúp vậ t, mà phía trên không cóứ ng việ n, cho nên không thể đ i lên mà phảiđ i xuố ng, không thể dùngđượ c nữ a.', 'u màđấ ng quân tửvẫ n muố n là việ c làmơ n cho thiênhạ , khiế n cho thiên hạv ượ t qua cả nh khố n. Cuố i cùngđứccủ a họcũ ng thấ u tai ngườ i trên. Là kẻ có tài, có thể nuôi ngườ i giúp vậ t, mà phía trên không cóứ ng việ n, cho nên không thể đ i lên mà phảiđ i xuố ng, không thể dùngđượ c nữ a.') ON CONFLICT (hexagram_id, line_number) DO UPDATE SET meaning_static = EXCLUDED.meaning_static, meaning_active = EXCLUDED.meaning_active;
INSERT INTO lines (hexagram_id, line_number, relation, meaning_static, meaning_active) VALUES (18, 3, '', 'Tiế n lui hayởlạiđề u khôngđượ c cả , chỉ còn có chế t mà thôi. Giế ng trong sạ ch mà khôngđượ c ngườ i dùngđế n tứ c là người có tài trí mà không đượ c dùng.', 'Tiế n lui hayởlạiđề u khôngđượ c cả , chỉ còn có chế t mà thôi. Giế ng trong sạ ch mà khôngđượ c ngườ i dùngđế n tứ c là người có tài trí mà không đượ c dùng.') ON CONFLICT (hexagram_id, line_number) DO UPDATE SET meaning_static = EXCLUDED.meaning_static, meaning_active = EXCLUDED.meaning_active;
INSERT INTO lines (hexagram_id, line_number, relation, meaning_static, meaning_active) VALUES (18, 4, '', 'Tà không thể thắ ng chính Nế u chọ n kẻ thếlự c mà theo, thì là ác lớ n. Kẻ tài tuy khôngđủ thi thốrộ ng rãi, làm lợ i cho ngườ i, nhưng có thểtự giữlấ y mình.', 'Tà không thể thắ ng chính Nế u chọ n kẻ thếlự c mà theo, thì là ác lớ n. Kẻ tài tuy khôngđủ thi thốrộ ng rãi, làm lợ i cho ngườ i, nhưng có thểtự giữlấ y mình.') ON CONFLICT (hexagram_id, line_number) DO UPDATE SET meaning_static = EXCLUDED.meaning_static, meaning_active = EXCLUDED.meaning_active;
INSERT INTO lines (hexagram_id, line_number, relation, meaning_static, meaning_active) VALUES (18, 5, '', 'Vua bị khố n vì thiên hạ không lạ i. Nế u có ngườ i cùng với thì không còn khố n. Giế ng phả i vọ t lên mớ i là thành công, chưa đế n bậ c trên thìchư a tớ i sự dùng.', 'Vua bị khố n vì thiên hạ không lạ i. Nế u có ngườ i cùng với thì không còn khố n. Giế ng phả i vọ t lên mớ i là thành công, chưa đế n bậ c trên thìchư a tớ i sự dùng.') ON CONFLICT (hexagram_id, line_number) DO UPDATE SET meaning_static = EXCLUDED.meaning_static, meaning_active = EXCLUDED.meaning_active;
INSERT INTO lines (hexagram_id, line_number, relation, meaning_static, meaning_active) VALUES (18, 6, '', 'Dùng thành ýđể lôi kéo hiề n nhân thì không bị khố n nữ a. Thể theo công dụ ng củ a giế ng, raơ n rộ ng mà có thường độ , phibậ c ngườ i lớ n thì ai làm nỗ i?', 'Dùng thành ýđể lôi kéo hiề n nhân thì không bị khố n nữ a. Thể theo công dụ ng củ a giế ng, raơ n rộ ng mà có thường độ , phibậ c ngườ i lớ n thì ai làm nỗ i?') ON CONFLICT (hexagram_id, line_number) DO UPDATE SET meaning_static = EXCLUDED.meaning_static, meaning_active = EXCLUDED.meaning_active;
