INSERT INTO hexagrams (id, name, palace, vietnamese_meaning, overall_meaning, career_meaning, love_meaning, wealth_meaning, health_meaning) VALUES (20, 'Thủy Lôi Truân', 'Khảm', 'Thủy Lôi Truân', 'Gian truân, khó khăn ban đầu, cần kiên trì bền bỉ vượt qua trở ngại.', 'Gian truân, khó khăn ban đầu, cần kiên trì bền bỉ vượt qua trở ngại.', 'Gian truân, khó khăn ban đầu, cần kiên trì bền bỉ vượt qua trở ngại.', 'Gian truân, khó khăn ban đầu, cần kiên trì bền bỉ vượt qua trở ngại.', 'Gian truân, khó khăn ban đầu, cần kiên trì bền bỉ vượt qua trở ngại.') ON CONFLICT (id) DO UPDATE SET overall_meaning = EXCLUDED.overall_meaning;
INSERT INTO lines (hexagram_id, line_number, relation, meaning_static, meaning_active) VALUES (20, 1, '', 'có tài nế u không quanh co mà vộ i tiế n lên thì lâm vào tai nạ n. Chị u khó chờ thờ i. Phả i dùng hình phạ t trừ ng trịmớ i cở i mở cái gông cùmđượ c. Khi có kế t qủ a rồ i thì thôi,đừ ng quá dùng hình phạ t mà sẽânhậ n.', 'có tài nế u không quanh co mà vộ i tiế n lên thì lâm vào tai nạ n. Chị u khó chờ thờ i. Phả i dùng hình phạ t trừ ng trịmớ i cở i mở cái gông cùmđượ c. Khi có kế t qủ a rồ i thì thôi,đừ ng quá dùng hình phạ t mà sẽânhậ n.') ON CONFLICT (hexagram_id, line_number) DO UPDATE SET meaning_static = EXCLUDED.meaning_static, meaning_active = EXCLUDED.meaning_active;
INSERT INTO lines (hexagram_id, line_number, relation, meaning_static, meaning_active) VALUES (20, 2, '', '(Khố n khổ , khó khă n nhưngườ i cở i ngự a còn dùng dằ ng,lẩ n quẩ n)', 'Đế n 10 nă m thì nạnđã lâu,ắ t phả i hanh thông. Bao dung kẻmờtố i, tố t. Dung nạ p hạ ng ngườ i nhu ám như đàn bà, tố t.Ở ngôi dướ i mà gánh vác việ c trên nhưngườ i con trai cai quả n việ c nhà.') ON CONFLICT (hexagram_id, line_number) DO UPDATE SET meaning_static = EXCLUDED.meaning_static, meaning_active = EXCLUDED.meaning_active;
INSERT INTO lines (hexagram_id, line_number, relation, meaning_static, meaning_active) VALUES (20, 3, '', 'i hươ u mà không có thợsă n giúp thì sẩ y vào rừng thôi.) Ngườ i quân tử hiể u cơsự ấ y thì bỏ đ i còn hơ n, cứ tiế p tụ c hànhđộ ng thì sẽhố i hậ n. Con gái theo ng ườ i phả i có chính lễ , vậ y mà ngườ i này thấ y kẻ nhiề u tiề n mà theo, không thể giữ đượ c thân mình, thì khôngđiđ âuđượ c lợ i.', 'i hươ u mà không có thợsă n giúp thì sẩ y vào rừng thôi.) Ngườ i quân tử hiể u cơsự ấ y thì bỏ đ i còn hơ n, cứ tiế p tụ c hànhđộ ng thì sẽhố i hậ n. Con gái theo ng ườ i phả i có chính lễ , vậ y mà ngườ i này thấ y kẻ nhiề u tiề n mà theo, không thể giữ đượ c thân mình, thì khôngđiđ âuđượ c lợ i.') ON CONFLICT (hexagram_id, line_number) DO UPDATE SET meaning_static = EXCLUDED.meaning_static, meaning_active = EXCLUDED.meaning_active;
INSERT INTO lines (hexagram_id, line_number, relation, meaning_static, meaning_active) VALUES (20, 4, '', 'c vớ i ngườ i trên mà tài không đủlướ t qua cảnh truân cho nên muố n tiế n lạ i thôi. Như ng nế u biế t người hiề n nhânởdướ i mà dùng, thì làm gì không đượ c? Chỉ nên tìm kẻcươ ng minh gầ n gũ i thì có thểvượ t qua. Hạng ngu tố i mà khôngđượ c gầ n ngườ i hiề n. 2', 'c vớ i ngườ i trên mà tài không đủlướ t qua cảnh truân cho nên muố n tiế n lạ i thôi. Như ng nế u biế t người hiề n nhânởdướ i mà dùng, thì làm gì không đượ c? Chỉ nên tìm kẻcươ ng minh gầ n gũ i thì có thểvượ t qua. Hạng ngu tố i mà khôngđượ c gầ n ngườ i hiề n. 2') ON CONFLICT (hexagram_id, line_number) DO UPDATE SET meaning_static = EXCLUDED.meaning_static, meaning_active = EXCLUDED.meaning_active;
INSERT INTO lines (hexagram_id, line_number, relation, meaning_static, meaning_active) VALUES (20, 5, '', 'Phả i lầ n lầ n chỉnhđố n các việ c nhỏ đã, nế u vộ i làm việclớ n thì hỏ ng. Trẻ thơchưađượ c mở mang, còn phả i nhờngườ i khác. Lấ y tư cách nhu thuậ n màở ngôi vua. Bỏ mình theo ngườ i.', 'Phả i lầ n lầ n chỉnhđố n các việ c nhỏ đã, nế u vộ i làm việclớ n thì hỏ ng. Trẻ thơchưađượ c mở mang, còn phả i nhờngườ i khác. Lấ y tư cách nhu thuậ n màở ngôi vua. Bỏ mình theo ngườ i.') ON CONFLICT (hexagram_id, line_number) DO UPDATE SET meaning_static = EXCLUDED.meaning_static, meaning_active = EXCLUDED.meaning_active;
INSERT INTO lines (hexagram_id, line_number, relation, meaning_static, meaning_active) VALUES (20, 6, '', 'c hiể m mà không có ng ườ i giúp. Cùng quẩn đếnnỗ i khóc ra máu mắt đầmđìa. Ở trên cùngđánh kẻtố i tă m. Như ng hànhđộ ng thái quá thìắt trởlạ i làm hạ i. Chỉ có ngă n sự cám dỗ bê nngoài,đểtừtừ xoadầ n nhữ ng mê muộ i bên trong. Lợ i vềsựchố ng giặ c, lài vì  kẻ trên ngườ i dướiđềuđồ ng thuậ n vớ i  mình.', 'c hiể m mà không có ng ườ i giúp. Cùng quẩn đếnnỗ i khóc ra máu mắt đầmđìa. Ở trên cùngđánh kẻtố i tă m. Như ng hànhđộ ng thái quá thìắt trởlạ i làm hạ i. Chỉ có ngă n sự cám dỗ bê nngoài,đểtừtừ xoadầ n nhữ ng mê muộ i bên trong. Lợ i vềsựchố ng giặ c, lài vì  kẻ trên ngườ i dướiđềuđồ ng thuậ n vớ i  mình.') ON CONFLICT (hexagram_id, line_number) DO UPDATE SET meaning_static = EXCLUDED.meaning_static, meaning_active = EXCLUDED.meaning_active;
