INSERT INTO hexagrams (id, name, palace, vietnamese_meaning, overall_meaning, career_meaning, love_meaning, wealth_meaning, health_meaning) VALUES (23, 'Thủy Thiên Nhu', 'Khôn', 'Thủy Thiên Nhu', 'Chờ thời cơ, dưỡng sức nuôi lòng, không nên nôn nóng vội vàng.', 'Chờ thời cơ, dưỡng sức nuôi lòng, không nên nôn nóng vội vàng.', 'Chờ thời cơ, dưỡng sức nuôi lòng, không nên nôn nóng vội vàng.', 'Chờ thời cơ, dưỡng sức nuôi lòng, không nên nôn nóng vội vàng.', 'Chờ thời cơ, dưỡng sức nuôi lòng, không nên nôn nóng vội vàng.') ON CONFLICT (id) DO UPDATE SET overall_meaning = EXCLUDED.overall_meaning;
INSERT INTO lines (hexagram_id, line_number, relation, meaning_static, meaning_active) VALUES (23, 1, '', 'đợ i vì gặ p chỗ hiể m, cho nênđợ i rồ i mớ i tiế n. Kẻ ởnơirộ ng xa, không dám xông pha vào chỗ hiể m nạ n màđ i. Nhu nhượcởdướ i, tài không thể kiệ n, dẫ u không kéo dài công việ c củ a mình, màđã kiệ n rồ i,ắ t có hạ i nhỏ , cho nên mắ c phải tai tiế ng.', 'đợ i vì gặ p chỗ hiể m, cho nênđợ i rồ i mớ i tiế n. Kẻ ởnơirộ ng xa, không dám xông pha vào chỗ hiể m nạ n màđ i. Nhu nhượcởdướ i, tài không thể kiệ n, dẫ u không kéo dài công việ c củ a mình, màđã kiệ n rồ i,ắ t có hạ i nhỏ , cho nên mắ c phải tai tiế ng.') ON CONFLICT (hexagram_id, line_number) DO UPDATE SET meaning_static = EXCLUDED.meaning_static, meaning_active = EXCLUDED.meaning_active;
INSERT INTO lines (hexagram_id, line_number, relation, meaning_static, meaning_active) VALUES (23, 2, '', 'n dầ n gầ n chỗ hiể m, tuy chư a phả i lo sợ , nhưngđã hơi có tiế ng luậ n bàn. Cươ ng trung mà biế t chờ đợ i thì sau chótđượ c tố t. Phả i trố n, là cố t tránh chỗ làm kẻ đốiđị ch. Từdướ i kiệ n lên, hoạ n nạ n tớ i. Khôngđượ c kiệ n.', 'n dầ n gầ n chỗ hiể m, tuy chư a phả i lo sợ , nhưngđã hơi có tiế ng luậ n bàn. Cươ ng trung mà biế t chờ đợ i thì sau chótđượ c tố t. Phả i trố n, là cố t tránh chỗ làm kẻ đốiđị ch. Từdướ i kiệ n lên, hoạ n nạ n tớ i. Khôngđượ c kiệ n.') ON CONFLICT (hexagram_id, line_number) DO UPDATE SET meaning_static = EXCLUDED.meaning_static, meaning_active = EXCLUDED.meaning_active;
INSERT INTO lines (hexagram_id, line_number, relation, meaning_static, meaning_active) VALUES (23, 3, '', 'Phả i chờ đợ i rồ i sẽ tiế n. Không phả i là ră n ngườ i ta khôngđượ c tiế n, chỉ muố n khiế n cho ngườ i ta chớ đểlỗ i mấ t cơ nghi mà thôi. Lấyđứ c và nhân nghĩ a xửxự theo bả n lãnh sẵ n có củ a mình mà kiên cốtự giữ . Tuyởchỗ hiể m nghèo mà lo lắ ng thì sau chót đượ c tố t lành.', 'Phả i chờ đợ i rồ i sẽ tiế n. Không phả i là ră n ngườ i ta khôngđượ c tiế n, chỉ muố n khiế n cho ngườ i ta chớ đểlỗ i mấ t cơ nghi mà thôi. Lấyđứ c và nhân nghĩ a xửxự theo bả n lãnh sẵ n có củ a mình mà kiên cốtự giữ . Tuyởchỗ hiể m nghèo mà lo lắ ng thì sau chót đượ c tố t lành.') ON CONFLICT (hexagram_id, line_number) DO UPDATE SET meaning_static = EXCLUDED.meaning_static, meaning_active = EXCLUDED.meaning_active;
INSERT INTO lines (hexagram_id, line_number, relation, meaning_static, meaning_active) VALUES (23, 4, '', 'trong hiể m nạ n, không thểcố ở , cho nên tự hang chui ra. Xuôi thuậnđể nghe theo thờ i. Ở yên, giữ đượ c hòa thuậ n là tố t. Cứ ng mạ nh mà không trung chính, thì hay nóng nả y hànhđộ ng thì không yên.', 'trong hiể m nạ n, không thểcố ở , cho nên tự hang chui ra. Xuôi thuậnđể nghe theo thờ i. Ở yên, giữ đượ c hòa thuậ n là tố t. Cứ ng mạ nh mà không trung chính, thì hay nóng nả y hànhđộ ng thì không yên.') ON CONFLICT (hexagram_id, line_number) DO UPDATE SET meaning_static = EXCLUDED.meaning_static, meaning_active = EXCLUDED.meaning_active;
INSERT INTO lines (hexagram_id, line_number, relation, meaning_static, meaning_active) VALUES (23, 5, '', 'ở yên màđợ i. Nế u là ngườ i xử kiệ n thì là bậ c hiềnđứ c, nế u là ngườiđ i kiện thì gặ p quan tòa công minh, không gì tố t bằ ng.', 'ở yên màđợ i. Nế u là ngườ i xử kiệ n thì là bậ c hiềnđứ c, nế u là ngườiđ i kiện thì gặ p quan tòa công minh, không gì tố t bằ ng.') ON CONFLICT (hexagram_id, line_number) DO UPDATE SET meaning_static = EXCLUDED.meaning_static, meaning_active = EXCLUDED.meaning_active;
INSERT INTO lines (hexagram_id, line_number, relation, meaning_static, meaning_active) VALUES (23, 6, '', 'xem gặ p chỗ hãm hiể m, như ng vớ i nhữ ng ngườ i phi ý màđế n, cứ kính trọ ng màđãi lạ i họ , thì sauđượ c tố t. Kẻrấ t thích kiệ n và dù may mắ n thắ ng kiệ n thì chẳ ng bao lâusẽmấ t hế t. Kế t qủ a vẫ n là tay không.', 'xem gặ p chỗ hãm hiể m, như ng vớ i nhữ ng ngườ i phi ý màđế n, cứ kính trọ ng màđãi lạ i họ , thì sauđượ c tố t. Kẻrấ t thích kiệ n và dù may mắ n thắ ng kiệ n thì chẳ ng bao lâusẽmấ t hế t. Kế t qủ a vẫ n là tay không.') ON CONFLICT (hexagram_id, line_number) DO UPDATE SET meaning_static = EXCLUDED.meaning_static, meaning_active = EXCLUDED.meaning_active;
