INSERT INTO hexagrams (id, name, palace, vietnamese_meaning, overall_meaning, career_meaning, love_meaning, wealth_meaning, health_meaning) VALUES (29, 'Phong Hỏa Gia Nhân', 'Tốn', 'Phong Hỏa Gia Nhân', 'Người trong nhà, tề gia trị quốc, giữ gìn nề nếp gia phong tốt đẹp.', 'Người trong nhà, tề gia trị quốc, giữ gìn nề nếp gia phong tốt đẹp.', 'Người trong nhà, tề gia trị quốc, giữ gìn nề nếp gia phong tốt đẹp.', 'Người trong nhà, tề gia trị quốc, giữ gìn nề nếp gia phong tốt đẹp.', 'Người trong nhà, tề gia trị quốc, giữ gìn nề nếp gia phong tốt đẹp.') ON CONFLICT (id) DO UPDATE SET overall_meaning = EXCLUDED.overall_meaning;
INSERT INTO lines (hexagram_id, line_number, relation, meaning_static, meaning_active) VALUES (29, 1, '', 'Biế t ngă n sự tiế n mớiđượ c không lỗ i. Khônglượ ng tài lự c mà tiế n, rút lạ i, chư a thểtự mình tiế n lên.', 'Biế t ngă n sự tiế n mớiđượ c không lỗ i. Khônglượ ng tài lự c mà tiế n, rút lạ i, chư a thểtự mình tiế n lên.') ON CONFLICT (hexagram_id, line_number) DO UPDATE SET meaning_static = EXCLUDED.meaning_static, meaning_active = EXCLUDED.meaning_active;
INSERT INTO lines (hexagram_id, line_number, relation, meaning_static, meaning_active) VALUES (29, 2, '', 'y theo vậ t khác thì mấ t cái sở thủcủ a mình. Khôngchị u trọngđãi ngườ i hiềnđể thi hành cáiđạ o củ a mình.Chớ đuổ i, tự nhiên sẽ đượ c.Cứ ng quá thì hay xúc phạ m ngườ i trên.Đươ ng thì khó nhọ c, kẻ nhờcậyđượ c là bề tôi có tài, càng nên hế t lòng kính thuậ n.', 'y theo vậ t khác thì mấ t cái sở thủcủ a mình. Khôngchị u trọngđãi ngườ i hiềnđể thi hành cáiđạ o củ a mình.Chớ đuổ i, tự nhiên sẽ đượ c.Cứ ng quá thì hay xúc phạ m ngườ i trên.Đươ ng thì khó nhọ c, kẻ nhờcậyđượ c là bề tôi có tài, càng nên hế t lòng kính thuậ n.') ON CONFLICT (hexagram_id, line_number) DO UPDATE SET meaning_static = EXCLUDED.meaning_static, meaning_active = EXCLUDED.meaning_active;
INSERT INTO lines (hexagram_id, line_number, relation, meaning_static, meaning_active) VALUES (29, 3, '', 'Việ c trong thiên hạ đã xong, màđ i xađánh kẻbạ o loạ n. Oai vũtớiđượ c, mà lấ y sựcứ u dân làm lòng. Chớ dùng kẻ tiể u nhân, vỉkẻ tiể u nhân có ý tham.Ởchỗ hiể m không cóđồ dùngđể ra chỗ hiể m màđ i thì hung.Ắ t phả i ra khỏ i chỗ hiểmđã, rồ i mớiđiđượ c. Kẻ đ i có thểvượtnướ c mà không thể đ i cạ n.', 'Việ c trong thiên hạ đã xong, màđ i xađánh kẻbạ o loạ n. Oai vũtớiđượ c, mà lấ y sựcứ u dân làm lòng. Chớ dùng kẻ tiể u nhân, vỉkẻ tiể u nhân có ý tham.Ởchỗ hiể m không cóđồ dùngđể ra chỗ hiể m màđ i thì hung.Ắ t phả i ra khỏ i chỗ hiểmđã, rồ i mớiđiđượ c. Kẻ đ i có thểvượtnướ c mà không thể đ i cạ n.') ON CONFLICT (hexagram_id, line_number) DO UPDATE SET meaning_static = EXCLUDED.meaning_static, meaning_active = EXCLUDED.meaning_active;
INSERT INTO lines (hexagram_id, line_number, relation, meaning_static, meaning_active) VALUES (29, 4, '', 'Trọ n ngày ră n sợ , là thườ ng ngờrằ ng vạ lo sắ p tớ i. Làm cho thiên hạ quá sự gian nan, nế u không có tài lớ n thì không làm nỗ i.', 'Trọ n ngày ră n sợ , là thườ ng ngờrằ ng vạ lo sắ p tớ i. Làm cho thiên hạ quá sự gian nan, nế u không có tài lớ n thì không làm nỗ i.') ON CONFLICT (hexagram_id, line_number) DO UPDATE SET meaning_static = EXCLUDED.meaning_static, meaning_active = EXCLUDED.meaning_active;
INSERT INTO lines (hexagram_id, line_number, relation, meaning_static, meaning_active) VALUES (29, 5, '', 'Thị nh soạ n không bằngđơ n sơ . Trố ng rỗ ng trong lòngđểcầ u kẻdướ i giúp mình.', 'Thị nh soạ n không bằngđơ n sơ . Trố ng rỗ ng trong lòngđểcầ u kẻdướ i giúp mình.') ON CONFLICT (hexagram_id, line_number) DO UPDATE SET meaning_static = EXCLUDED.meaning_static, meaning_active = EXCLUDED.meaning_active;
INSERT INTO lines (hexagram_id, line_number, relation, meaning_static, meaning_active) VALUES (29, 6, '', 'xem không biế t ră n sợ , tứ c là nguy.Uố ng rượ u thái quá là không biế t tiếtđộ. LÝ SINH KHẮ C TRONG 64 Ý TƯỢNG Để giảiđáp thắ c mắ c củađ a sốhọ c viên hỏ i tạ i sao 1 Dị ch tượ ng xem ra tố t mà lạ i xấ u, xấ u mà lạ i tố t; và không biế t xả y ra cho mình hay cho ng ườ i hoặ c cho vậ t khác. Sauđây là bả ng ý thứ c chính xác cươ ng vịcủ a mình trong mỗ i sự việ c luôn luôn có 4 chiề u:- Khi tađộ ng chỉ có 2 chiề u: Ta sinh hoặ c bị khắ c kẻ khác.- Khi ta tĩ nh cũ ng có 2 chiề u:Kẻ khác hoặ c sinh hoặ c khắ c ta. Trong kiế p sinh thành củ a con ngườ i và muôn vậ t lúc nào cũ ng chỉ làĐộ ng Tĩ nh. Có lúc chúng ta Tự Độ ng, có lúc bị độ ng hoặ c thụ độ ng. Chúng ta không nên thiên chấ p lý luậ n 1 chiề u: Mộ t Dị ch tượ ng chẳ ng xấ u mà cũ ng chẳ ng tố t. Tố t xấ u là tùy theo từ ng việ c, từ ng vấnđề riêng tưcủ a ta mà thôi. Còn Dị ch lý thì vô tư . Lý luậnbị hayđược đó là do chủ quan củamỗ i ngườ i. Mong các bạ n nhậnđị nh cho kỹ. 1. KHÔN : Thuậ n dã là mề m mỏ ng. Ta bị nhu nhượ c. Tađượ c sự nhu thuậ n. (Ta tĩ nh) Ta mề m mỏ ng vớ i kẻ khác. Ta nhu nh ượ c vớ i kẻ khác. (Tađộ ng) 2. PHỤC : Phả n dã là trởlạ i, tái hồ i. Ta bị phả n hồ i. Tađượ c sự trởvề. Ta phụ c hư ng cho kẻ khác. Ta phả n bộ i kẻ khác. 3. LÂM:Đạ i dã là lớnở trên soi xuố ng. Ta bị giáo hoá. Tađượ c giáo dụ c. Ta giáo tư , dung chở cho kẻ khác. Ta tự đạ i vớ i kẻ khác. 4. THÁI : Thông dã là hanh thông. Ta bị thông tri. Tađượ c thông hiể u. Ta khai thông cho kẻ khác. Ta thông thạ o hơ n ngườ i. 5. TRÁNG : Chí dã là chí khí bề n. Ta bịlậ p nên. Ta cóđượ c chí khí. Ta chí chính cho kẻ khác. Ta hùng tráng vớ i kẻ khác. 6. QUẢI : Quyế t dã là quyếtđ oán, dứ t khoát. Ta bịdứ t quyế t. Tađượ c sự quyếtđị nh. Ta dứ t khoát, phán cho kẻ khác. Ta cươ ng quyế t cắtđứ t kẻ khác. 7. NHU : Thuậ n dã là chờ đợ i nhu cầ u. Ta bị nghiệ m xét. Tađượ c cứ u xét. 18 Ta nghiên cứ u cho kẻ khác. Ta nghiệ m xét kẻ khác. 8. TỶ : Thân dã, tư dã là hân hoan, thân liề n. Ta bịtư thân. Tađượ c tư thân. Ta cầ u thân vớ i kẻ khác. Ta cở i bỏmọ i ngườ i. 9. CẤN : Chỉ dã là ngă n giữ. Ta bịngă n chặ n. Tađượ c ngă n chặ n. Ta ngă n ngừ a cho kẻ khác. Ta ngă n giữkẻ khác. 10. BÍ : Sứ c dã là trang sứ c, thông suố t. Ta bị thấ u suố t. Tađượ c sáng suố t. Ta sáng tỏ cho kẻ khác. Tađả thông kẻ khác. 11. ĐẠI SÚC : Tụ dã là chứ a lớ n. Ta bị tích tụ . Tađượ c tích tụ. Ta nuôi chứ a kẻ khác. Ta dồ n tụkẻ khác. 12. TỔN : Thấ t dã, hao tổ n, thấ t bác. Ta bị hao tổ n. Tađượ c ban bố. Ta ban bố cho kẻ khác. Ta tổ n hạ i kẻ khác. 13. KHUỂ : Quai dã là trái lìa, nhờ vã lẫ n nhau. Ta bịhổ trợ . Tađượ c hổ trợ. Ta hổ trợ cho kẻ khác. Tađượ c thếlự c hùng hổvớ i kẻ khác. 14. LÝ : Lễ dã là lễ phép, hệ thố ng qui. Ta bị theo phép. Tađượ c lễ kính. Ta lể kính kẻ khác. Ta bắ t lỗ i kẻ khác. 15. TRUNG PHU :    Tín dã là tín cẩ n. Ta bị ủ y nhiệ m. Tađượ c tín nhiệ m. Ta tin tưở ng kẻ khác. Taủ y nhiệ m kẻ khác. 16. TIỆM : Tiế n dã là tiế n bộlầ n lầ n. Ta bị tuầ n tự . Tađượ c tiệ m tiế n. Ta thứtự cho kẻ khác. Ta chậ m chạ p và trậ t tựkẻ khác. 17. KHẢM : Hãm dã là hiể m nguy, bắ t buộ c. Ta bị hãm hiể m. Tađượ c kề m hãm. Ta chị u sựkề m hãm cho kẻ khác. Tađóng khung kẻ khác. 18. TIẾT : Chỉ dã là chừ ng mự c, hạ n chế. Ta bịhạ n chế . Tađượ c hạ n chế. Ta tiế t kiệ m cho kẻ khác. Ta tiế t chếkẻ khác. 19. TRUÂN : Nạ n dã là khó khă n, trởngạ i. Ta bị gian nan. Tađượ c cứ u khổ. Ta truân chuyên vì kẻ khác. Ta gây gian truân kẻ khác. 20. KÝ TẾ : Hợ p dã là hợ p pháp. Ta bịhợ p cùng. Tađượ c hiệ p nhau. Ta hợ p lý cho kẻ khác. Ta cấ u hợ p kẻ khác. 21. CÁCH : Cả i dã là thayđổ i. Ta bịcả i biế n. Tađượ c hoán cả i. Ta hoàn thiệ n cho kẻ khác. Ta biế n chếkẻ khác. 22. PHONG : Thị nh dã là thịnhđạ i, lớ n. Ta bị đồ ng hóa. Tađượ c hòađồ ng. Ta hòađồ ng vớ i kẻ khác. Tađồ ng hóa vớ i kẻ khác. 23. MINH DI : Thươ ng dã là bị thươ ng. Ta bị thươ ng. Tađượ c thươ ng hạ i. Tađ au thươ ng vì kẻ khác. Ta gây tang th ươ ng cho kẻ khác. 24. SƯ : Chúng dã,ủ ng hộ nhau, nhiề u ngườ i. Ta bịáp chúng. Ta đượ c chúngủ ng hộ. Taủ ng hộkẻ khác. Tađượ c chúngủ ng hộ. 25. TỐN : Nhậ p dã là thuậ n, vàoở trong. Ta bị sát nhậ p. Tađượ c gia nhậ p. Ta thuậ n nhậ p, vào ra vớ i kẻ khác. Ta du nhậ p,độ t nhậ p kẻ khác. 26. TIỂU SÚC : Tắ c dã là chứ a góp ít. Ta bị côđơ n. Tađượ c riêng ý. Tađộcđáo vì kẻ khác. Ta cô lậ p hay là bấtđiệ u vớ i kẻ khác. 27. GIA NHÂN:Đồ ng dã là cùng nhau. Ta bị thêm ngườ i. Tađượ c sinh sôi nẩ y nở. Ta sinh sôi cho kẻ khác. Tađồ ng hóa kẻ khác làm giađ inh. 28. ÍCH : Ích dã là tă ng thêm, ích lợ i. Ta bịlợ i dụ ng. Tađượ c lợ i ích. Ta ban lộ c cho ngườ i. Ta lợ i dụ ng kẻ khác. 29. VÔ VỌNG : Thiên tai dã là tai nạ n tự nhiên. Ta bị xâm lấ n. Tađượ c xâm phạ m. Ta chị u sự xâm nhậ p. Ta xâm phạ m kẻ khác. 30. PHÊ HẠP : Khiế t dã là cắ n hợ p, hỏ i han. Ta bị đ ay nghiế n. Tađượ c cắ n hợ p. Ta chị u sự dày xéo. Tađ ay nghiế n kẻ khác. 31. DI : Dưỡ ng dã là chă m lo, nuôi nấ ng. Ta bị an nghỉ . Tađượ c bồ i dưỡ ng. Ta bổdưỡ ng cho kẻ khác. Ta an nghỉkẻ khác. 32. CỔ : Sự dã là cớsự , việ c. Ta bịcớsự . Tađượ c cớsự, Ta chị u cớsự cho kẻ khác. Ta gây cớsựvớ i kẻ khác. 33. CHẤN:Độ ng dã là chấnđộ ng, dấ y khở i. Ta bị kinhđộ ng. Tađượ c dấyđộ ng. Ta hoạtđộ ng cho kẻ khác. Ta gây kinh độ ng cho kẻ khác. 34. DỰ : Duyệ t dã là phòng bị , vui vẻ. 19 Ta bị múa rố i. Tađượ c vuiđộ ng. Tađộ ng vui cho kẻ khác. Ta múa rố i, rộ n tan kẻ khác. 35. GIẢI : Thuậ n dã là phân tán, cở i mở , giảiđãi. Ta bị phân tán. Tađượ c phóng thích. Ta phóng thích cho kẻ khác. 36. HẰ NG:Cử u dã là lâu, bề n vữ ng. Ta bị kéo dài. Tađượ c bề n vữ ng. Ta bề n chặ t vớ i kẻ khác. Tađ eo theo kẻ khác. 37. THĂ NG: Tiế n dã là vọ t lên,đ i không trởlạ i. Ta bịhố i hả . Tađượ c mau chóng. Ta số t sắ ng cho kẻ khác. Ta hố i thúc kẻ khác. 38. TĨNH : Tị nh dã là trầ m lặ ng, sâu. Ta bị dìm sâu. Tađượ c yên lặ ng. Tađ em sự bình an cho kẻ khác. Ta dìm sâu kẻ khác. 39. ĐẠI QUÁ : Quá dã là nhiề u quá, thái quá. Ta bị qúađỗ i. Tađượ c tích cự c. Ta tích cự c cho kẻ khác. Ta qúađộvớ i kẻ khác. 40. TÙY : Thuậ n dã là theo. Ta bịlệ thuộ c. Tađượ c tùy nghi. Ta chìu chuộ ng kẻ khác. Ta lệ thuộ c hóa kẻ khác. 41. LY : Lệ dã là sáng sủ a, bám vào, phụ vào. Ta bị tranh sáng. Tađượ c sáng sủ a. Ta sáng tỏ cho kẻ khác. Ta tranh sáng vớ i kẻ khác. 42. LỮ : Khách dã là khách,ở trọ , lữ thứ. Ta bị lang thang. Tađượ c khách qúy. Ta bằ ng lòng choở đỗ . Ta tá ngụ nhà ngườ i. 43. ĐỈNH:Đị nh dã là nung nấ u, úngđúc. Ta bị nung nấ u. Tađượ c ungđúc. Ta ungđúc kẻ khác. Ta nungđố t kẻ khác. 44. VỊ TẾ : Thấ t dã là thấ t bác, dỡ dang. Ta bịdở dang. Ta nhờsựdở dang. Ta thấ t bác cho kẻ khác. Ta phá hỏ ng kẻ khác. 45. MÔNG : Muộ i dã là mờmị t, tố i tă m. Ta bịám muộ i. Tađượ c sựám muộ i. Ta cheđậ y mờám cho kẻ khác. Ta bấ t minh vớ i kẻ khác. 46. HOÁN : Tán dã là tan ra, lìa tan. Ta bị xa lánh. Tađượ c xa lánh. Ta phi tang cho kẻ khác. Ta tan biế n kẻ khác. 47. TỤNG : Luậ n dã là luậ n bàn, kiệ n cáo. Ta bị tranh tụ ng. Tađượ c sự biệ n minh. Ta biệ n luậ n cho kẻ khác. Ta gây gỗ kiệ n tụ ng kẻ khác. 48. ĐỒNG NHÂN : Thân dã là gầ n gũ i, cùng chung vớ i người khác. Ta bị yêu chuộ ng. Tađượ c sự đồ ng ý. Ta biểuđồ ng tình vớ i kẻ khác. Ta ngang hàng thấ t kính kẻ khác. 49. Đ OÀI : Duyệ t dã là vui lòng, hiện đẹ p. Ta bị đùa cợ t. Tađượ c vuiđẹ p. Ta vuiđẹ p cho kẻ khác. Ta cườ i chê,đùa cợ t kẻ khác. 50. KHỐN : Nguy dã là lo âu, nguy khố n. Ta bị nguy khố n. Tađượ c lo lắ ng. Ta lo lắ ng cho kẻ khác. Ta làm nguy khố n kẻ khác. 51. TỤY : Tụ dã, tụhọ p, tụlạ i mà khôngđ i. Ta bị trư ng tậ p. Tađượ c tụtậ p. Ta cổ độ ng cho kẻ khác. Ta trư ng tậ p kẻ khác. 52. HÀM : Cả m dã là cả m xúc. Ta bịcảmđộ ng. Tađượ c cả m tươ ng. Ta tươ ng cảmđế n kẻ khác. Ta làm xúc độ ng kẻ khác. 53. KIỂN : Nạ n dã là hoạ n nạ n, khó khă n. Ta bị trởngạ i. Tađượ c sựngă n trở. Ta ngă n ngừ a cho kẻ khác. Ta chướ ng ngạ i kẻ khác. 54. KHIÊM : Thoái dã là lui lạ i, nhún nhườ ng. Ta bị miệ t thị . Tađượ c nhún nhườ ng. Ta khiêm tố n vớ i kẻ khác. Ta miệ t thịkẻ khác. 55. TIỂU QUÁ : Quá dã là nhỏ quá, thiể u lý. Ta bị hèn hạ . Tađượ c phậ n mọ n. Tađ oái hoàiđế n kẻ khác. Ta phiề n nhiễ u kẻ khác. 56. QUI MUỘI : Tai dã là tai nạ n, rố i ren. Ta bị đẹpđộ ng. Tađượcđẹpđộ ng. Ta chị u sựrố i ren cho kẻ khác. Ta khuấ y rố i kẻ khác. 57. KIỀN : Kiệ n dã là mạ nh mẽ. Ta bịsứ c mạ nh. Tađượ c lớ n mạ nh. Ta hùng mạ nh cho kẻ khác. Ta cườ ng bạ o vớ i kẻ khác. 58. CẤU : Ngộ dã là gặ p gỡ. Ta bịbắ t gặ p. Tađượ c cấ u kế t. Ta mai mố i cho kẻ khác. Ta bắ t gặ p kẻ khác. 59. ĐỘN : Thoái dã là luiẩ n, trốnđ i. Ta bị ẩ n trố n. Tađượcẩ n trố n. Ta che dấ u cho kẻ khác. Taẩ n trố n kẻ khác. 60. BĨ : Tắ c dã là bếtắ c. Ta bịbếtắ c. Tađượ c sựbếtắ c. Ta bếtắ c cho kẻ khác. Ta tắ c nghẽ n kẻ khác. 20 61. QUÁN : Quan dã là xem xét, quan sát. Ta bị quan sát. Tađượ c xem xét. Ta trông nom cho kẻ khác. Ta quan sát kẻ khác. 62. BÁC : Lạ c dã là bớ t, lộ t mấ t. Ta bịlộ t xác. Tađượ c xoá mờ. Ta xoá nhòa cho kẻ khác. Ta lộ t xác kẻ khác. 63. TẤN : Tiế n dã làđế n hayđ i, tiế n tớ i. Ta bị đ i. tađượcđế n. Ta hiệ n diệ n cho kẻ khác. Ta xuồ ng xãđế n kẻ khác. 64. ĐẠI HỮU : Khoan dã là cả có. Ta bị trùngđiệ p. Ta cóđượ c nhiề u. Ta phong phú cho kẻ khác. Tađ a sựvớ i kẻ khác. QuiƯớcĐ oán Qủ e HẬ U THIÊN 1. Dùng bả ng vạ n vậ t (Bả ng I) mà suy ra th ượ ng quái. 2. Dùng bả ng phươ ng hướ ng (Bả ng II)để suy ra hạ quái. 3. Gia thêm giờ để tính hàođộ ng. Bả ng I Càn quái Trờ i_Cha_Ông già_Qúi_Quan_ Đầ u_Xươ ng_Ngự a_Vàng_Châu báu _Ngọ c_Cây qủ a_Vậ t hình tròn_Mũ _Gươ ng_Vậ t cứ ng_Sắcđỏ thẫm _Nướ c lạ nh. Chấ n quái Sấ m_Trưở ng nam_Chân_Tóc__Rồ ng_Loài sâu bọ _Móng chân thú _Tre_Cỏ lau_Ngự a hí_Ngón chân cái_Trán_Trồ ng lúa_Nhạ c khí _Cỏ cây_Sắ c xanh_Biế c_Lụ c_Cây lớ n_Hạ t cây lớ n_Củ i_Rắ n. Khả m quái Nướ c_Mư a tuyế t_Lợ n_Trung nam (trai thứ )_Ngòi_Rãnh nướ c_ _Cây cung_Vành bánh xe_Tai_Huyế t_Mặ t tră ng_Kẻ trộ m_Cung luậ t (đồ dùng về thanh âm)_Bụ i gai_Cá_Nóc nhà_Cỏtậ t lê _Chồ n cáo_Cái 