INSERT INTO hexagrams (id, name, palace, vietnamese_meaning, overall_meaning, career_meaning, love_meaning, wealth_meaning, health_meaning) VALUES (40, 'Hỏa Địa Tấn', 'Ly', 'Hỏa Địa Tấn', 'Tiến lên, được lòng tin dùng của cấp trên, thăng tiến rộng mở.', 'Tiến lên, được lòng tin dùng của cấp trên, thăng tiến rộng mở.', 'Tiến lên, được lòng tin dùng của cấp trên, thăng tiến rộng mở.', 'Tiến lên, được lòng tin dùng của cấp trên, thăng tiến rộng mở.', 'Tiến lên, được lòng tin dùng của cấp trên, thăng tiến rộng mở.') ON CONFLICT (id) DO UPDATE SET overall_meaning = EXCLUDED.overall_meaning;
INSERT INTO lines (hexagram_id, line_number, relation, meaning_static, meaning_active) VALUES (40, 1, '', 'Cuộ c tan cứ u vớ t từ lúcđầ u, thì dễ dùng sứ c, vì là thì thuậ n. Ră n nó giữ gìn cẩ n thậ n.', 'Cuộ c tan cứ u vớ t từ lúcđầ u, thì dễ dùng sứ c, vì là thì thuậ n. Ră n nó giữ gìn cẩ n thậ n.') ON CONFLICT (hexagram_id, line_number) DO UPDATE SET meaning_static = EXCLUDED.meaning_static, meaning_active = EXCLUDED.meaning_active;
INSERT INTO lines (hexagram_id, line_number, relation, meaning_static, meaning_active) VALUES (40, 2, '', 'ng thì lìa tan màở trong chỗ hiể m. Nế u mà có thể chạ y tớ i chỗ yên thì tố t. Sự dè dặ t bấ t chính, như keo cú vềsự dùng, nhút nhát về việc làm.', 'ng thì lìa tan màở trong chỗ hiể m. Nế u mà có thể chạ y tớ i chỗ yên thì tố t. Sự dè dặ t bấ t chính, như keo cú vềsự dùng, nhút nhát về việc làm.') ON CONFLICT (hexagram_id, line_number) DO UPDATE SET meaning_static = EXCLUDED.meaning_static, meaning_active = EXCLUDED.meaning_active;
INSERT INTO lines (hexagram_id, line_number, relation, meaning_static, meaning_active) VALUES (40, 3, '', 'Tài không trung chính, lênở vào chỗ không ngôi, há cứu đượ c sự lìa tan trong thì mình mà để ơ n tớ i ngườ i ta? Chẳ ng dè dặ t thì than thởvậ y,ấ y là tự mình làm ra không thể đổlỗ i cho ai. Dè dặ t thì có thể khỏ i lỗ i.', 'Tài không trung chính, lênở vào chỗ không ngôi, há cứu đượ c sự lìa tan trong thì mình mà để ơ n tớ i ngườ i ta? Chẳ ng dè dặ t thì than thởvậ y,ấ y là tự mình làm ra không thể đổlỗ i cho ai. Dè dặ t thì có thể khỏ i lỗ i.') ON CONFLICT (hexagram_id, line_number) DO UPDATE SET meaning_static = EXCLUDED.meaning_static, meaning_active = EXCLUDED.meaning_active;
INSERT INTO lines (hexagram_id, line_number, relation, meaning_static, meaning_active) VALUES (40, 4, '', 'Vua tôi hợ p sứcđểcứ u vớ t cuộ c tan cho thiên hạ . Lạ i nói tanđượcđàn nhỏ, để làm nênđàn lớ n, thìđó không phả i là việ c mà ngườ i tầ m thườ ng nghĩ đượ c tớ i nơ i. Nướ c tràn lên là không tiết độ , chẩ y xuố ng là có tiếtđộ . Không phả i gượ ng mà dè dặ t, tứ c là yên lòng vớ i sự dè dặ t.', 'Vua tôi hợ p sứcđểcứ u vớ t cuộ c tan cho thiên hạ . Lạ i nói tanđượcđàn nhỏ, để làm nênđàn lớ n, thìđó không phả i là việ c mà ngườ i tầ m thườ ng nghĩ đượ c tớ i nơ i. Nướ c tràn lên là không tiết độ , chẩ y xuố ng là có tiếtđộ . Không phả i gượ ng mà dè dặ t, tứ c là yên lòng vớ i sự dè dặ t.') ON CONFLICT (hexagram_id, line_number) DO UPDATE SET meaning_static = EXCLUDED.meaning_static, meaning_active = EXCLUDED.meaning_active;
INSERT INTO lines (hexagram_id, line_number, relation, meaning_static, meaning_active) VALUES (40, 5, '', 'Vua tôi hợ p sứ c, nhún thuậ n chữ a cuộ c tan làđúng cáchrồ i, chỉcố t làm cho thấ m khắ p lòng ngườ i thì họ thuận theo. Ở mình thì yên lòng mà làm thiên hạ thìđẹ p lòng mà theo,đó là cuộ c dè dặ t ngọ t ngon. Sự dè dặ t lấ y vừ a phả i làm qúi.', 'Vua tôi hợ p sứ c, nhún thuậ n chữ a cuộ c tan làđúng cáchrồ i, chỉcố t làm cho thấ m khắ p lòng ngườ i thì họ thuận theo. Ở mình thì yên lòng mà làm thiên hạ thìđẹ p lòng mà theo,đó là cuộ c dè dặ t ngọ t ngon. Sự dè dặ t lấ y vừ a phả i làm qúi.') ON CONFLICT (hexagram_id, line_number) DO UPDATE SET meaning_static = EXCLUDED.meaning_static, meaning_active = EXCLUDED.meaning_active;
INSERT INTO lines (hexagram_id, line_number, relation, meaning_static, meaning_active) VALUES (40, 6, '', 'Thì tan, lấ y sựhợpđượ c là có công, cho nên lấ y sự ra khỏ i cuộ c tan, xađượcđiề u hạ i là hay. Sự dè dặtđã khổ mà cố giữ thì hung.', 'Thì tan, lấ y sựhợpđượ c là có công, cho nên lấ y sự ra khỏ i cuộ c tan, xađượcđiề u hạ i là hay. Sự dè dặtđã khổ mà cố giữ thì hung.') ON CONFLICT (hexagram_id, line_number) DO UPDATE SET meaning_static = EXCLUDED.meaning_static, meaning_active = EXCLUDED.meaning_active;
INSERT INTO hexagrams (id, name, palace, vietnamese_meaning, overall_meaning, career_meaning, love_meaning, wealth_meaning, health_meaning) VALUES (41, 'Hỏa Sơn Lữ', 'Ly', 'Hỏa Sơn Lữ', 'Lữ khách hành trình xa nhà, bất định, cần thận trọng khi làm việc nơi đất khách.', 'Lữ khách hành trình xa nhà, bất định, cần thận trọng khi làm việc nơi đất khách.', 'Lữ khách hành trình xa nhà, bất định, cần thận trọng khi làm việc nơi đất khách.', 'Lữ khách hành trình xa nhà, bất định, cần thận trọng khi làm việc nơi đất khách.', 'Lữ khách hành trình xa nhà, bất định, cần thận trọng khi làm việc nơi đất khách.') ON CONFLICT (id) DO UPDATE SET overall_meaning = EXCLUDED.overall_meaning;
