INSERT INTO lines (hexagram_id, line_number, relation, meaning_static, meaning_active) VALUES (44, 2, '', 'i cóđứ c trung chính thì có thể ở yên nơ i chố n của mình vìđộ ng thì hung.  Kẻ nóng nả y thì làm cànđạ i. Biếtđượ c trọ ng khinh, cử độ ng chừ ng mự c thì không bị ă n nă n.', 'i cóđứ c trung chính thì có thể ở yên nơ i chố n của mình vìđộ ng thì hung.  Kẻ nóng nả y thì làm cànđạ i. Biếtđượ c trọ ng khinh, cử độ ng chừ ng mự c thì không bị ă n nă n.') ON CONFLICT (hexagram_id, line_number) DO UPDATE SET meaning_static = EXCLUDED.meaning_static, meaning_active = EXCLUDED.meaning_active;
INSERT INTO lines (hexagram_id, line_number, relation, meaning_static, meaning_active) VALUES (44, 3, '', 'Có tánh cúng nóng, mà không biế t tự giữ mà chí lạ i thích theo ngườ i,ấ y là hèn thấ p vậ y. Đượ c chỗ thườ ng mà không chịuở thì sựhổnhụ c cũ ng tớ i.', 'Có tánh cúng nóng, mà không biế t tự giữ mà chí lạ i thích theo ngườ i,ấ y là hèn thấ p vậ y. Đượ c chỗ thườ ng mà không chịuở thì sựhổnhụ c cũ ng tớ i.') ON CONFLICT (hexagram_id, line_number) DO UPDATE SET meaning_static = EXCLUDED.meaning_static, meaning_active = EXCLUDED.meaning_active;
INSERT INTO lines (hexagram_id, line_number, relation, meaning_static, meaning_active) VALUES (44, 4, '', 'i tỏ cáiđạ o liề n muố n tính cái công ví  như thấyđứ a trẻ ngã vào trong giế ng, vừ a muố n cứ u nó, vừ a muố n cha mẹ nó khen mình tửtế , chưađượ c sáng lớ n vì không hợ p lẽtự nhiên. Sự làm củ a ngườ i ta hễ mà phảiđạ o thì lâu mãi sẽ thành công,nế u không phảiđạ o, dù lâu mà có ích gì?Ở không phả i ngôi, không phả i chỗ , dẫ u thườ ng theo giữ có ích gì?', 'i tỏ cáiđạ o liề n muố n tính cái công ví  như thấyđứ a trẻ ngã vào trong giế ng, vừ a muố n cứ u nó, vừ a muố n cha mẹ nó khen mình tửtế , chưađượ c sáng lớ n vì không hợ p lẽtự nhiên. Sự làm củ a ngườ i ta hễ mà phảiđạ o thì lâu mãi sẽ thành công,nế u không phảiđạ o, dù lâu mà có ích gì?Ở không phả i ngôi, không phả i chỗ , dẫ u thườ ng theo giữ có ích gì?') ON CONFLICT (hexagram_id, line_number) DO UPDATE SET meaning_static = EXCLUDED.meaning_static, meaning_active = EXCLUDED.meaning_active;
INSERT INTO lines (hexagram_id, line_number, relation, meaning_static, meaning_active) VALUES (44, 5, '', 'u tráiđượ c lòng riêng, kẻcả m không phả i là người mìnhđã trông thấ y màđẹ p lòng, thìđượ c chínhđạ o. Tuy không vướ ng víu lòng riêng, như ng không thểcả m người thì chí củ a nó nhỏnhặ t lắ m. Đàn bà lấ y sự theo làmđạ o chính Nếuđấ ng trượ ng phu cũnglấ y sự thuậ n theo ngườ i ta làm nế t thườ ng, thì là mấ t sự chínhđính củ a mình, vậ y là hung.', 'u tráiđượ c lòng riêng, kẻcả m không phả i là người mìnhđã trông thấ y màđẹ p lòng, thìđượ c chínhđạ o. Tuy không vướ ng víu lòng riêng, như ng không thểcả m người thì chí củ a nó nhỏnhặ t lắ m. Đàn bà lấ y sự theo làmđạ o chính Nếuđấ ng trượ ng phu cũnglấ y sự thuậ n theo ngườ i ta làm nế t thườ ng, thì là mấ t sự chínhđính củ a mình, vậ y là hung.') ON CONFLICT (hexagram_id, line_number) DO UPDATE SET meaning_static = EXCLUDED.meaning_static, meaning_active = EXCLUDED.meaning_active;
INSERT INTO lines (hexagram_id, line_number, relation, meaning_static, meaning_active) VALUES (44, 6, '', 'm ngườ i bằ ng lờ i nói mà không có sự thậ t thì háđộngđượ c ngườ i. Xố c làđộ ng 1 cách nhanh chóng. Nế u mà nóngđộ ng bất thườ ng thì còn nênđượ c trò gì? Sự thườngđã cùng tộ t thànhbấ t thườ ng.', 'm ngườ i bằ ng lờ i nói mà không có sự thậ t thì háđộngđượ c ngườ i. Xố c làđộ ng 1 cách nhanh chóng. Nế u mà nóngđộ ng bất thườ ng thì còn nênđượ c trò gì? Sự thườngđã cùng tộ t thànhbấ t thườ ng.') ON CONFLICT (hexagram_id, line_number) DO UPDATE SET meaning_static = EXCLUDED.meaning_static, meaning_active = EXCLUDED.meaning_active;
