INSERT INTO lines (hexagram_id, line_number, relation, meaning_static, meaning_active) VALUES (46, 6, '', '(áo giáp, mũsắ t)_Binh khí_Vă n thơ _Lò_Cây khô_Rùa_Con trai (hế n, sò) _Vỏ các loài vậ t_Màuđỏ _Hồ ng_Tía_Hoa_Vă n nhân_Vậ t khô ròn_Con cua. Tố n quái Gió_Trưở ng nữ _Tă ng ni_Đùi_Bách cầ m_Bách thả o_Cốiđá_Mùi thơ m_Mùi hôi thố i_Mặ t_Buồ m_Lông chim_Lông thú_Chiế c quạ t_Cành lá các loại _Tiênđạ o_Thợ _Vậ t thẳ ng_Đồ công xả o_Gà. Đ oài quái Hồ_Đầ m_Thiế u nữ (Gái út)_Thay cáp_L ướ i_Vợlẽ _Chổ i_Con dê_Đồvật sứ t mẻ_Đồvậ t có miệ ng_Loài thuộ c Kim_Vậ t phế _Khuyế t_Nô bộ c_Tỳ. Số Lý Dị ch Tượng Danh Tượng Ý Tượng 1 Thiên KiềnCƯƠ NG KIỆN .Kiệ n dã; mạ nh mẽ , mạ nh tiế n, cứ ng mạ nh, khỏemạ nh, khô, lớ n, cao.2 TrạchĐ oài HIỆNĐẸP .Duyệ t dã; vui lòng, đẹpđẽ,ư a thích, khuyế t mẽ , nóină ng.3 Hỏa Ly SÁNG CHÓI .Lệ dã; sáng sủ a, tỏ a ra, bám vào, phụ vào, trư ng bày, phô trươ ng, trố ng trơ n, không yên.4 LôiChấnĐỘ NG DỤNG.Độ ng dã; rungđộ ng, khở i lên, sợ hãi, phấ n phát, nổ vang, chấnđộ ng, chấ n kinh.5 PhongTốn THUẬ N NHẬP .Thuậ n dã; thuậ n theo ý trên, theo lên, theo xuố ng, theo tớ i theo lui, có sự giấ u diếmở trong.6 Thủy Khảm HÃM HIỂM .Hãm dã; hãm vào trong, bắ t buộ c, xuyên sâu vào trong,hố sâu, trắ c trở , hiể m hóc, gậ p ghề nh. 227 SơnCấnNGƯ NG NGHỈ .Chỉ dã; ngă n giữ,ở , thôi, ngừ ng lạ i,đậ y lạ i,để dành, ngă n cấ m, vừađúng chỗ.8 Địa Khôn NHU THUẬN .Thuậ n dã; mề m mỏ ng, thuậ n tòng, hòa theo lẽ , chịulấ y, tuân theo mà đượ c lợ i. Bả ng II Ly: Phươ ng Nam Khảm: Phươ ng Bắc Chấn: PhươngĐôngĐ oài: Phươ ng Tây Tốn: PhươngĐông NamCấn: PhươngĐông Bắc Càn: Phươ ng Tây Bắc Khôn: Phươ ng Tây nam QUÁI KHÍ VƯỢ NG & SUY VƯỢ NG: -  Chấ n, Tố n thuộ c Mộ c vượngở mùa Xuân. -  Ly thuộ c Hỏ a vượngở mùa Hạ. -  Càn,Đ oài thuộ c Kim vượngở mùa Thu. -  Khả m thuộ c Thủ y vượngở mùaĐông. -  Khôn, Cấ n thuộ c Thổvượngởnhữ ng tháng cuố i mỗ i mùa: Thìn, Tuấ t, Sử u, Mùi (tháng 3, 6, 9 và 12)', 'SUY: -  Khôn, Cấ n thuộ c Thổ suyở mùa Xuân. -  Càn,Đ oài thuộ c Kim suyở mùa Hạ. -  Chấ n, Tố n thuộ c Mộ c suyở mùa Thu. -  Ly thuộ c Hỏ a suyở mùaĐông. -  Khả m thuộ c Thủ y suyởnhữ ng tháng cuố i mỗ i mùa: Thìn, Tuấ t, Sử u, Mùi (tháng 3, 6, 9 và 12). THẬ P THIÊN CAN -  Giáp,Ấ t      thuộ c     Mộc PhươngĐông. -  Bính,Đ inh    ---        Hỏa ---         Nam -  Mậ u, Kỷ ---        Thổ ---         Trung Ương -  Canh, Tân    ---        Kim ---         Tây -  Nhâm, Qúy  ---        Thủy ---         Bắc THẬ P NHỊ ĐỊ A CHI 23- Tý          (Thủ y)        1                    -  Sử u         (Thổ )         2 -  Dầ n          (Mộ c)          3                    -  Mão        (Mộ c)         4 -  Thìn          (Thổ )          5                    -  Tỵ (Hỏ a)        6 -  Ngọ (Hỏ a)          7                    -  Mùi          (Thổ )         8 -  Thân        (Kim)           9                    -  Dậ u          (Kim)        10 -  Tuấ t         (Thổ )           11                   -  Hợ i          (Thủ y)       12 NGŨ HÀNH TỨ THỜ I VƯỢ NG, TƯỚ NG,Ư U, TÙ Mùa Vượng Tướng Hưu Tù Xuân Mộ c Hỏ a Thủ y Thổ HạHỏ a ThổMộ c Kim Thu Kim Thủ y ThổMộcĐông Thủ y Mộ c Kim Hỏa Các tháng 3, 6, 9, 12 Thổ Kim Hỏ a Thủy BÁT QUÁI TƯỢNGĐỒ CÀN KHÔN CHẤN CẤN Tam LiênLụcĐoạ n Ngưỡ ng Bồ n Phúc Uyển LY KHẢM Đ OÀI TỐN Trung Hư Trung Mãn Thượ ng Khuyế t Hạ Đoạn THỨTỰHƯỚ NG DẪ N CÁCH "THẦM KIỂ M SOÁT" MỘ T SỰ LÝ 1. Muố n phát hiệnđượ c mộ t hoặ c nhiề u khuôn mặtĐỘ NG-TĨ NH, cùng lúcẩ n tàng trong SỰ - LÝ. 2. Phả i nhớDỊ CH-TƯỢ NG hiệ n có,đượ c ví như là mộ t THIÊN DIỆNĐ ANG CỰ C. VÍ DỤ THỨNHỨ T: Nă m Bính NgọSố Lý ThứTự là        7 Tháng ba                                                                   3 Ngày Mườ i Bố n                                                      14 ------------- 24 24 -  (8 x 3) GiờTị +     6 ------------- 30 - (8 x 3) (6 x 5) CHÁNH TƯỢ NG: 3. Phảiđị nh rõ PHẠ M VI TÌNH LÝ muố n phát hiệ n. THÍ DỤ: Có mộ t ngườ i bạ n quenđ em mộ t cái máy thu thanh đổ i tầ ng số (máy có nhiề u bă ng tâng chạ y pin mộ t chiề u bị KÊU TỪ NG CHẶPđế n nhờ tôi sữ a dùm. SỰ LÝ: Cái Radio  KÊU TỪ NG CHẶ P là Phạ m Vi Tình Lý thuộ c phầ n PHÁT ÂM. 4. Phả i nêu ra hế t TÍNH LÝĐƯƠ NG NHIÊN củ a mỗ i TÌNH LÝ LIÊN HỆ trong Phạ m Vi Sự Lý. Thông thườ ng, mộ t máy thu thanh đổtầ ng sốgồ m có: a/. Bộ PhậnĐiề u Chỉ nh/Thâu Sóng: Nhiệ m vụ (Tánh LýĐươ ng Nhiên): Lự a sóngđiệ n do nhiềuđài phát thanh phát ra vớ i nhiề u tầ ng số khác nhau. b/- Bộ Phậ n KhuếchĐạ i Cao Tầ ng: Nhiệ m vụ (Tánh LýĐươ ng Nhiên):  Nhiề u sóngđiệnđế n dây thâu sóng rấ t yế u, cầ n phả i làm mạ nh lên, rồiđư a qua bộ phậ n khác. c/- Bộ Phậ n KhuếchĐạ i Trung Tầ ng: Nhiệ m vụ (Tánh LýĐươ ng Nhiên):Đổ i tầ ng số ra mộ t tầ ng số phù hợ p và khuếchđạ i tầ ng sốvừađổ i. d/- Bộ Phậ n KhuếchĐạ i HạTầ ng/Tách Sóng: Nhiệ m vụ (Tánh LýĐươ ng Nhiên): Tách sóng đểhủ y bỏ làn sóng biếnđiệ u chuyên chỡ , và lậ p lạ i dòngđiệ n, thayđổ i thành hạtầ ng rồ i khuếchđạ i mạ nh lên. e/- Bộ Phậ n KhuếchĐạ i Xuấ t Âm: Nhiệ m vụ (Tánh LýĐươ ng Nhiên): Tiế p rướ c dòngđiệ n hạtầ ng,đổ i ra tiế ng nói hay âm nhạ c dođài phát thanh phát ra. f/- Bộ Phậ n Tiế p Tế (Pin hoặcĐiệ n): Nhiệ m vụ (Tánh LýĐươ ng Nhiên): Cung cấpđiệ n thế cao hoặ c thấ p (Pin:điệ n thế thấ p) cho các nơ i tiêu thụ trong máy. LƯỢCĐỒ: 25 5. Phả i SO SÁNH ý nghĩ a củ a THIÊN DIỆNĐ ANG CỰ C vớ i Tính LýĐươ ng Nhiên củ a mỗ i Tình Lý Liên Hệ trong Phạ m Vi Sự Lý. 6. Phả i hiể u rằ ng CHỈ CÓ MỘT Tính LýĐươ ng Nhiên củ a mộ t Tình Lý Liên Hệ nghiêng nặ ng về phía Thiên DiệnĐ ang Cự c hơ n các Tình Lý khác gọ i là PHẠ M VI CHÁNHĐỘ NG. So sánh Tính Lý "CHÚNG TRỢ " củ a Dị ch Tượ ng SƯ , vớ i Tính LýĐươ ng nhiên củ a Từ ng Bộ Phậ n trong chiế c máy thu thanh phát ra từ ng chặ p. Ta thấ y chỉ có Bộ Phậ n Tiế p tế Pin: Cung cấpđiệ n thế cao hoặ c thấ p cho các nơi tiêu thụ trong máy thích hợ p vớ i ý nghĩ a SƯnhấ t. Dođó BỘ PHẬ N TIẾ P TẾ là Phạ m Vi ChánhĐộ ng có liên hệ đế n phầ n phát âm từ ng chặ p. 7. Phả i biếnđổ i ý nghĩ a củ a Thiên DiệnĐ ang Cự c thành mộ t Ý MỚ I thích hợ p vớ i tình lý mà ng ườiđờiđã gán ghép cho Phạ m Vi ChánhĐộ ng gọ i là DANH LÝ BIẾ N THÔNG. Danh Lý Biế n Thông ------------>  củ a Dị ch Tượ ng        SƯ đổ i thành ý mớ i là ---------------->  Bộ Phậ n Tiế p Tế :     PIN 8. Nế u có trườ ng hợ p DANH LÝ BIẾ N THÔNG hiệ n có, chư a phả i là Danh Lý cuố i cùng thì phả i bắtđầ u trởlạivớ i các Qui Tắcđã dẫ n từmụ c số3ở đoạ n trướ c. Phân tích tiế p chođế n khi không còn tìm thấ y mộ t Danh Lý nào khác mớ i thôi. BƯỚ C 1: Phạ m Vi Tình Lý:Bộ Phậ n Tiế p Tế (Pin) Tình Lý Liên Hệ: - Pin - Dây Chuyề n Pin - Cắ m Tiế p Pin Tình LýĐươ ng Nhiên: - Pin:          Tích và phátđiệ n thế thấ p. - Dây:        Chuyề n dẫ n pin (dẫnđiệ n) - Cắ m:        Tiế p tế pin thẳ ng vào máy (truyềnđiệ n). So sánh Tính Lý "CHÚNG TRỢ " củ a Dị ch Tượ ng SƯvớ i Tính Lý củ a cái Cắ m Tiế p Pin. Ta thấ y, cái Cắm Tiế p Pin thích hợ p vớ i ý nghĩ a SƯ. CÁI CẮ M TIẾ P PIN là Phạ m Vi ChánhĐộ ng có liên hệ đế n phầ n phát âm từ ng chậ p. BƯỚ C 2: Phạ m Vi Tình Lý: Cái Cắ m Tiế p Pin Tình Lý Liên Hệ: - Cái lõi sắt - Dây Chuyề n Pin - Cắ m Nắ p Vặn Tình LýĐươ ng Nhiên: 26 - Lõi sắ t:          cắ m vào máy. - Dây:              chuyề n dẫ n pin (dẫnđiệ n) - Nắ p Vặ n:       giữ cho hai mố i dây không chạ m vào nhau. So sánh Tính Lý "CHÚNG TRỢ "  củ a Dị ch Tượ ng SƯvớ i Tình Lý củ a cái nắ p vặ n. Ta thấ y cái nắ p vặ n thíchhợ p vớ i cái nghĩ a SƯ. CÁI NẮ P VẶN là Phạ m Vi ChánhĐộ ng có liên hệ đế n phầ n phát âm từ ng chặ p. BƯỚ C 3: Phạ m Vi Tình Lý: Cái Nắ p Vặ n (nằ m bên trong) Tình Lý Liên Hệ: - Hai que sắ t nhỏ - Hai sợ i dây - Hai mố i chì Tình LýĐươ ng Nhiên: - Que sắ t nhỏ :        móc nố i dây vào lõi sắ t. - Sợ i dây:               chuyề n dẫ n pin (dẫnđiệ n) - Mố i Chì Hàn:       giúp cho dây dính vớ i que sắ t nhỏ. So sánh Tính Lý "CHÚNG TRỢ "  củ a Dị ch Tượ ng SƯvớ i Tình Lý củ a CHÌ Hàn. Ta thấ y chì hàn cho mố i dây dính chặ t vớ i que sắ t thích hợ p vớ i cái nghĩ a SƯ. Như thế,MỐ I CHÌ - là Phạ m Vi ChánhĐộngđ úng lý vớ i ý nghĩaSƯ. - là Danh Lý biên Thông cuố i cùng, nhiệ m nhặtẩ n tàng trong Sự Lý PHÁT ÂM TỪ NG CHẶP. Kế t Luậ n: Nguyên nhân khiế n cho cái máy thu thanh đổ i tầ ng số , KÊU TỪ NG CHẶ P là do mố i chì hànđã bịlỏ ng sút ra ngoài. VÍ DỤ THỨ HAI: Mỗ i bữ a trư a, trướ c khiđế n nhà thă m mộ t cô bạ n, tôi thườ ng hay vẽsơlượ c mộ t kiể u áo ngắ n mà cô bạ n sẽmặc trong ngàyđể thí nghiệ m. 27 LUẬ N CHỨ NG: Đọ c hế t các Tình Ý kể trong câu chuyệ n. Ta thấ y: KIỂ U ÁO: Là phạ m Vi Tình Lýđãđượ c thu hẹp 1. Phả i hỏ i xem, LÚC LÒNG CẢ M XÚC muố n thầ m phác họ a, Thiên Diệ n nàođ ang cự c? NămĐ inh Mùi                     Số Lý ThứTự là           8 Tháng hai                                                                2 Ngày Mùng Nă m                                                      5 ------------- 15 -  (8 x 3) Giờ Mùi                                                              +     8 ------------- 23 - (8 x 3) (6 x 5) 2. Phả i lấ y Tính LýĐươ ng Nhiên củ a Thiên DiệnĐ ang Cự c (CHÁNH TƯƠ NG) lầ n lượ t kê vào các Tình Lý Liênhệ đểlấ y ra mộ t Danh Lý Biế n Thông sẵ n có trong Phạ m Vi Tình Lýđã giớ i hạnở trướ c. a)- Lấ y ý nghĩ a củ a Chánh Tượ ng Thuầ n Cấ n là NGĂ N CHE kê vào cái áo. Ta thấ y, ý nghĩ a NGĂ N CHE chỉ thích hợ p vớ i Tính LýĐươ ng Nhiên củaĐƯỜ NG VIỀ N trên cái áo. b)- Thườ ng thườ ng, áo củ a các cô có các đườ ng viề n như là: -Đườ ng viềnởchỗ Tá Áo, Vạ t Áo, Gấ u Áo. -Đườ ng viềnởchỗ Tay Áo. -Đườ ng viềnởchỗCổÁo, Bâu Áo, Túi Áo. 3. Phả i xem Tính LýĐươ ng nhiên củ a Tình Lý Liên hệ nào sát gầ n vớ i ý nghĩ a củ a Thiên DiệnĐ ang Cự c kèm theovị trí Hàođ angđộ ng nế u cầ n. Lấ y ý nghĩ a NGĂ N CHE và vị trí hàođộ ng thứ 5 lầ n lượ t kê vào cácđườ ng viề n kể trên. Ta thấ y chỉ cóđườ ng viề n trên cổáo là có nhiề u tình lý phác họ a thích hợ p nhấ t. ĐƯỜ NG VIỀ N CỔ là Phạ m Vi Tình Lý sát gấ n vớ i Thiên DiệnĐ ang Cự c. 4. Phả i nắ m ngay Tình Lý Liên Hệ đó, chiế t ra mộ t cặ p Tình LýĐốiĐãi tùy thuộ c ý nghĩ a củ a Chánh tượ ng. 5. Phả i so sánh Tính Lý ĐốiĐãi tùy thuộcđ ó vớ i ý nghĩ a củ a Thiên DiệnĐ ang Cự c (Chánh Tượ ng). 28 6. Phả i hiể u rằ ng, chỉ có mộ t trong hai Tính Lý ĐốiĐãi nổ i bậ t và nghiêng nặ ng về phía ý nghĩ a củ a Thiên DiệnĐ ang Cự c hơ n Tính LýĐốiĐãi kia. Lấyđườ ng viề n CONG so vớiđườ ng viề n NGAY theo ý nghĩ a Thuầ n Cấ n (Ngă n Che) thì thấ y: ĐƯỜ NG VIỀ N CONG thích hợ p vớ i ý tượ ng trên. 7. Phả i bám thậ t chắ c vào Danh Lý Biế n Thông hiệ n có, rồ i thể theo Tính LýĐươ ng Nhiên củ a CHÁNH và BIẾNT ƯỢ NG  (hoặ c CHÁNH -  HỘ - BIẾ N TƯỢ NG) mà vẽ tiế p ra mộ t hình bóngđơ n giả n, phù hợ p vớ i Tình Lýcủ a ThờiĐạ i, Dân Tộ c,Đị a Phươ ng. Că n cứ vào Danh Lý Biề n Thông hiệ n có, ta hỏ i: -Đườ ng viề n trên cổáo CONG như thế nào? Nế u ta lấ y ý nghĩ a củ a Biế n Tượ ng PHONG SƠ N TIỆ M là Tuầ n Tự kê vàoĐườ ng Cong trên cổ áo thì thấ y: -Đườ ng cong trên cổ áo có hình gãy gấ p giố ng như các bậ c thang, hế t bậ c nầyđế n bậ c khác. 8. Phả i kiể m lạ i xem, Danh Lý Biế n Thông nào có thể giúp ta nói hoặ c viế t cho ngườ i khácđọ c và nghe dễ dànhchấ p nhậnđượ c, gầ n hay nguyên vẹ n hình bóng ta vừ a phác họ a. Đườ ng Viề n Cong trên cổáo có hình giố ng như các bậ c thang xế p chồ ng lên nhauđược đổ i thành Danh Lý Biế n Thông có sẵ n trong ThờiĐạ i là: ÁO CỔ DÚN. 9. Trườ ng hợ p muố n vẽ thêm cho hình bóng vừ a phác họ a mộ t vài chi tiế t nữ a thì lấ y Tính LýĐươ ng Nhiên củaĐơ n TượngĐộngở Chánh, kề m vớ i Tính LýĐươ ng Nhiên củaĐơ n Tượ ng Biế n mà phác họ a..v..v..v.. VÍ DỤ THỨ BA: Mộ t hôm, ông bạ n tôi chỉ tay vào cái vỏ bìnhđự ng bình tích nướ c trà. Hắ n nói: "Chú thử đ oán xem Nướ c trong cái bình tích kia NÓNG hay NGUỘ I?" Xét trong ý hướ ng củ a ông bạ n. Ta thấ y: Ông nàyđ ang dồ n hế t cả m xúc muố n biế t vào Phạ m Vi Tình Lý " CÁIVỎ ĐỰ NG BÌNH TÍCH NƯỚ C TRÀ". 1. Phả i biế t trong Phạ m Vi Tình Lýđó, hiệ n tađ ang thắ c mắ c muố n hỏ i thuộ c về Lý,Đứ c, Tính, Thầ n, Khí, Tình, Thanh, Sắ c, Chấ t, Thể hay Hình ? Ví dụ : "Chú thử đ oán xem Nướcở trong cái bình tích kia NÓNG hay NGUỘ I?" LUẬ N CHỨ NG: Xét qua toàn ý câu hỏ i, ta thấ y: Ông bạ n kiađ ang chú ýđế n TÍNH Nóng - Nguộ i củ a Nướ c Tràđựngở trong cái bình tích. 2. Phả i nhớý nghĩ a củ a Thiên DiệnĐ ang Cự c,đượ c ví như là mộ t tấ m kínhđ a hiệ u, có thể soi rọ i vào bấ t cứ Không Thờ i Gian Vô Hữ u nào cũngđượ c. Nă m Bính NgọSố Lý ThứTự là           7 Tháng mườ i                                                              10 Ngày Hai Mươ i Hai                                                   22 ------------- 39 -  (8 x 4) GiờNgọ +    7 ------------- 46 - (8 x 5) 29 (6 x 7) CHÁNH TƯỢ NG: 3. Phả i phân tích cho đế n nhiệ m nhặ t, các Tình Lý Liên hệ trong câu hỏ i nêu rađể thấ y rõ Tình Lý nào là thenchố t. Chiế t tính Tình Lý trong câu hỏ i trên. Ta có: a)- Nóng - Nguộ i là cặ p Tình Lý có sẵ n thứnhứ t. b)- Nướ c là Tình Lý có sẵ n thứ nhì. c)- Trà là Tình Lý có sẵ n thứ ba. d)- Cái bình tích là Tình Lý có sẵ n cuố i cùng. 4. Phả i hỏ i xem Tình Lý có sẵ n nào làm chủ đượ c toàn chuỗ i tình lý, thể hiệ n trong câu hỏ i, rồ i nắ m ngay Tình Lýđ ó và ghi ra mộ t cặ p TÍNH LÝĐỐIĐÃI tùy thuộ c. Nhìn vào chuỗ i Tình Lý liên hệ trên. Ta thấ y: Cái BÌNH TÍCH là tình lý có giá trị then chố t. Dođó, tađặ t thành câu hỏ i như sau: " Cái BÌNH TÍCH  Có hay Không Có để ở trong cái vỏ bình?" 5. Phả i so sánh Tính Lý Đươ ng Nhiênđặ c tính chung củ a Thiên DiệnĐ ang Cự c vớ i Tính LýĐốiĐãi đặ c tính riêngcủ a sự lý cầ n trảlờ i. 6. Nế u có trườ ng hợ p: a)- Tính LýĐốiĐ ãi nêu ra khôngă n khớ p vớ i Chánh Tượ ng thì phả i lấ y Tính Lý củ a Biế n Tượ ng mà lý luậ n.Đôi khi có tr ườ ng hợ p phả i luậ n từngượ c từ Biên Tượ ng qua Chánh Tượ ng. b)- Nế u Biế n Tượ ng lạ i không hộiđủ lýđể trảlờ i nữ a thì phả i hợ p cả Chánh lẫ n Biế n, hoặ c CHÁNH - HỘ- BIẾ N chung lạ i làm mộ t Tam Quái Liên Quan, rồ i lý luậ n. c)- Ngoài ra, còn có thểlấ y vị trí củ a HàoĐộ ng hoặcĐơ n Tượngđộngđể trảlờ i cho các phạ m vi chi tiế t thuộcvề Không gian và Thờ i gian như xa gầ n, mau chậ m.... 7. Phả i hiể u rằ ng, chỉ có mộ t trong hai Tính Lý ĐốiĐãi, nổ i bậ t và nghiêng nặ ng vềý nghĩ a củ a Thiên DiệnĐ angCự c hơ n cả. So sánh Tính Lý "BẤ T MINH"  củ a Dị ch tượ ng MÔNG vớ i Tính LýĐốiĐãi: KHÔNG - CÓ thì thấ y ý nghĩ a BẤ T MINH thích hợ p vớ i Tính Lý KHÔNG hơ n là Tính Lý CÓ. Vậ y ta xácđị nh: 30 CÁI BÌNH TÍCH HIỆ N KHÔNG CÓỞ TRONG CÁI VỎ BÌNH 8. Phả i kiể m lạ i xem DANH LÝ BIẾ N THÔNG hiệ n cóđã dứ t khoát trảlờ i câu hỏiđã nêu ra chư a. Trườ ng hợ p chỉ mộ t câu trảlờ i mà câuđó có thểchặt đứtđượ c chuỗ i Tình Lý thì coi như câu hỏ i nêu rađãđượ c giảiđáp xong.. Trong trườ ng hợ p này,để trảlờ i câu hỏ i: " Chú thử đ oán xem Nướcở trong cái bình tích kia nóng hay nguộ i?" Ta có câu trảlờ i như sau: CÁI BÌNH TÍCH KHÔNG CÓ TRONG VỎ BÌNH THÌ LÀM GÌ CÓ N ƯỚ C NÓNG HAY NƯỚ C NGUỘ I. Ý NGHĨ A QUÁI VÀ HÀO Chính quái: Đầ u cuộcHộ quái    : Trung cuộc Biế n quái  :Kế t cuộc Tuy nhiên, có mộ t số t trườ ng hợ p thì Chính quái lạ i là Kế t cuộ c mà Biế n quái lạ i làĐầ u cuộ c tùy theo hiệ n trạ ng củ a ngườihỏiđ angđứ ng trong phạ m vi nào. Muố n toán dị ch cầ n phả i: 1. Hiể u ý nghĩ a củ a quái. 2. Xem hào nàođộ ng. 3.') ON CONFLICT (hexagram_id, line_number) DO UPDATE SET meaning_static = EXCLUDED.meaning_static, meaning_active = EXCLUDED.meaning_active;
