INSERT INTO hexagrams (id, name, palace, vietnamese_meaning, overall_meaning, career_meaning, love_meaning, wealth_meaning, health_meaning) VALUES (49, 'Trạch Sơn Hàm', 'Đoài', 'Trạch Sơn Hàm', 'Cảm ứng, giao cảm chân thành giữa nam nữ, đối tác hợp tác thuận lợi.', 'Cảm ứng, giao cảm chân thành giữa nam nữ, đối tác hợp tác thuận lợi.', 'Cảm ứng, giao cảm chân thành giữa nam nữ, đối tác hợp tác thuận lợi.', 'Cảm ứng, giao cảm chân thành giữa nam nữ, đối tác hợp tác thuận lợi.', 'Cảm ứng, giao cảm chân thành giữa nam nữ, đối tác hợp tác thuận lợi.') ON CONFLICT (id) DO UPDATE SET overall_meaning = EXCLUDED.overall_meaning;
INSERT INTO lines (hexagram_id, line_number, relation, meaning_static, meaning_active) VALUES (49, 1, '', 'đế n nơ i mà biế t lo hãi thì sẽ không có vạ lo, nhân sự lo sợ màđượ c phúc. Đángđậ u màđ i, không phả i là chính.', 'đế n nơ i mà biế t lo hãi thì sẽ không có vạ lo, nhân sự lo sợ màđượ c phúc. Đángđậ u màđ i, không phả i là chính.') ON CONFLICT (hexagram_id, line_number) DO UPDATE SET meaning_static = EXCLUDED.meaning_static, meaning_active = EXCLUDED.meaning_active;
INSERT INTO lines (hexagram_id, line_number, relation, meaning_static, meaning_active) VALUES (49, 2, '', 'i làđ i theo vậ t khác, thế là mấ t sựtự thủ , cho nên rănrằ ng chớ đuổ i. Nói không nghe, đạ o không thự c hành, cho nên lòng nó khôngs ướ ng.', 'i làđ i theo vậ t khác, thế là mấ t sựtự thủ , cho nên rănrằ ng chớ đuổ i. Nói không nghe, đạ o không thự c hành, cho nên lòng nó khôngs ướ ng.') ON CONFLICT (hexagram_id, line_number) DO UPDATE SET meaning_static = EXCLUDED.meaning_static, meaning_active = EXCLUDED.meaning_active;
INSERT INTO lines (hexagram_id, line_number, relation, meaning_static, meaning_active) VALUES (49, 3, '', 'u nhân sựnhứ c sợ mà biế t bỏ tà theo chính thì sẽ đượctố t. Cố đậ u không thể tiế n lui, lo vềsự hiể m nghèo thườ ng hunđốt trong lòng.', 'u nhân sựnhứ c sợ mà biế t bỏ tà theo chính thì sẽ đượctố t. Cố đậ u không thể tiế n lui, lo vềsự hiể m nghèo thườ ng hunđốt trong lòng.') ON CONFLICT (hexagram_id, line_number) DO UPDATE SET meaning_static = EXCLUDED.meaning_static, meaning_active = EXCLUDED.meaning_active;
INSERT INTO lines (hexagram_id, line_number, relation, meaning_static, meaning_active) VALUES (49, 4, '', 'không thểtự mình phấ n chấ n, cho nên nói "chìm đắ m", há có thể sáng. Không thể làm cho thiên hạ cùngđậ u, mà chỉ đậuđượ c thân mình, hàđủxứ ng ngôiđạ i thầ n?', 'không thểtự mình phấ n chấ n, cho nên nói "chìm đắ m", há có thể sáng. Không thể làm cho thiên hạ cùngđậ u, mà chỉ đậuđượ c thân mình, hàđủxứ ng ngôiđạ i thầ n?') ON CONFLICT (hexagram_id, line_number) DO UPDATE SET meaning_static = EXCLUDED.meaning_static, meaning_active = EXCLUDED.meaning_active;
INSERT INTO lines (hexagram_id, line_number, relation, meaning_static, meaning_active) VALUES (49, 5, '', 'i lên thì nó vố n là mề m,đ i xuố ng thì phạ m vào kẻcứ ng.Kẻ xem không mấtđứ c giữ a, tuy có nguy cũ ng không sao. Cái mà ngườ i ta cầ n phả i cẩ n thậ n là nói và làm. Nói ra bằng cách khinh xuấ t thì xấ u.', 'i lên thì nó vố n là mề m,đ i xuố ng thì phạ m vào kẻcứ ng.Kẻ xem không mấtđứ c giữ a, tuy có nguy cũ ng không sao. Cái mà ngườ i ta cầ n phả i cẩ n thậ n là nói và làm. Nói ra bằng cách khinh xuấ t thì xấ u.') ON CONFLICT (hexagram_id, line_number) DO UPDATE SET meaning_static = EXCLUDED.meaning_static, meaning_active = EXCLUDED.meaning_active;
INSERT INTO lines (hexagram_id, line_number, relation, meaning_static, meaning_active) VALUES (49, 6, '', 'ngác là dáng tan tác. Biế t lo sợ trướ c khi nó chư a tới mình thì khôngđế n nỗ i cùng cự c. Sự đậ u củ a ngườ i ta có chỉ khó giữ lâu tớ i chót, cho nên tiết tháo khi về già thìđổ i, công việ c có khiđế n lâu thì hỏ ng.', 'ngác là dáng tan tác. Biế t lo sợ trướ c khi nó chư a tới mình thì khôngđế n nỗ i cùng cự c. Sự đậ u củ a ngườ i ta có chỉ khó giữ lâu tớ i chót, cho nên tiết tháo khi về già thìđổ i, công việ c có khiđế n lâu thì hỏ ng.') ON CONFLICT (hexagram_id, line_number) DO UPDATE SET meaning_static = EXCLUDED.meaning_static, meaning_active = EXCLUDED.meaning_active;
