INSERT INTO lines (hexagram_id, line_number, relation, meaning_static, meaning_active) VALUES (52, 1, '', 'Tiể u nhân lấ n quân tử thậ t là hung. Dùng gi ườ ng làm "tượ ng" tượ ng trư ng chỗ mìnhở.Đẽođế n góc giườ ng rồ i. Tuy lầ m lỗ i như ng chẳ ng bao lâu lạ i trởlạ i tố t lành ngay. Chưađ i xa màđã trởlạ i conđườ ng thiệ n thì tố t.', 'Tiể u nhân lấ n quân tử thậ t là hung. Dùng gi ườ ng làm "tượ ng" tượ ng trư ng chỗ mìnhở.Đẽođế n góc giườ ng rồ i. Tuy lầ m lỗ i như ng chẳ ng bao lâu lạ i trởlạ i tố t lành ngay. Chưađ i xa màđã trởlạ i conđườ ng thiệ n thì tố t.') ON CONFLICT (hexagram_id, line_number) DO UPDATE SET meaning_static = EXCLUDED.meaning_static, meaning_active = EXCLUDED.meaning_active;
INSERT INTO lines (hexagram_id, line_number, relation, meaning_static, meaning_active) VALUES (52, 2, '', 'Tiể u nhân lấ n quân tử.Đươ ng lúc tiêu bác mà không có phe cánh, tựtồ n saođượ c. Biế t nhườ ng ngườ i nhânđứ c,đó là hànhđộ ng tốtđẹ p.', 'Tiể u nhân lấ n quân tử.Đươ ng lúc tiêu bác mà không có phe cánh, tựtồ n saođượ c. Biế t nhườ ng ngườ i nhânđứ c,đó là hànhđộ ng tốtđẹ p.') ON CONFLICT (hexagram_id, line_number) DO UPDATE SET meaning_static = EXCLUDED.meaning_static, meaning_active = EXCLUDED.meaning_active;
INSERT INTO lines (hexagram_id, line_number, relation, meaning_static, meaning_active) VALUES (52, 3, '', 'Có bụ ng theo về đườ ng chính, như thế không lỗ i. Bỏ bèđả ng mà theo kẻ ngay là không lỗ i. Luôn luônđánh mấ t nên mớ i nguy, trởlạ i thì không sao.', 'Có bụ ng theo về đườ ng chính, như thế không lỗ i. Bỏ bèđả ng mà theo kẻ ngay là không lỗ i. Luôn luônđánh mấ t nên mớ i nguy, trởlạ i thì không sao.') ON CONFLICT (hexagram_id, line_number) DO UPDATE SET meaning_static = EXCLUDED.meaning_static, meaning_active = EXCLUDED.meaning_active;
INSERT INTO lines (hexagram_id, line_number, relation, meaning_static, meaning_active) VALUES (52, 4, '', 'o chân giườ ng dầ n dầnđế n da. Da là bề ngoài thân thể , tứ c là sắ p diệ t thân thể cho nên gọ i là hung. Đ i vớ i nhiề u ngườ i mà mộ t mình biế t theođườ ng thiệ n.', 'o chân giườ ng dầ n dầnđế n da. Da là bề ngoài thân thể , tứ c là sắ p diệ t thân thể cho nên gọ i là hung. Đ i vớ i nhiề u ngườ i mà mộ t mình biế t theođườ ng thiệ n.') ON CONFLICT (hexagram_id, line_number) DO UPDATE SET meaning_static = EXCLUDED.meaning_static, meaning_active = EXCLUDED.meaning_active;
INSERT INTO lines (hexagram_id, line_number, relation, meaning_static, meaning_active) VALUES (52, 5, '', 't bà hoàng hậuđ em bầ y cung phi hầ u vua, không gì mà không lợ i. Phía dướ i không kẻ giúpđỡ , biế t dố c lòng phụ c thiệ n thì không phảiă n nă n.', 't bà hoàng hậuđ em bầ y cung phi hầ u vua, không gì mà không lợ i. Phía dướ i không kẻ giúpđỡ , biế t dố c lòng phụ c thiệ n thì không phảiă n nă n.') ON CONFLICT (hexagram_id, line_number) DO UPDATE SET meaning_static = EXCLUDED.meaning_static, meaning_active = EXCLUDED.meaning_active;
INSERT INTO lines (hexagram_id, line_number, relation, meaning_static, meaning_active) VALUES (52, 6, '', 'u bọ n tiể u nhân phá sậ p nhàđó làđạ o quân tửbị tiêu diệ t, quố c gia suy vong. Cái gì cự c thị nh thì trởlạ i thăngbằngđểtựtồ n. Kẻ tiể u nhân hôn mêđế n cự c cùng, không biế t trởlạ i nên bị đủ tai vạ.Ở trên muố n dùng võ lựcđàn áp như ng rố t cuộ c bị đạibạ i, gây vạ chođấ t nướ c.', 'u bọ n tiể u nhân phá sậ p nhàđó làđạ o quân tửbị tiêu diệ t, quố c gia suy vong. Cái gì cự c thị nh thì trởlạ i thăngbằngđểtựtồ n. Kẻ tiể u nhân hôn mêđế n cự c cùng, không biế t trởlạ i nên bị đủ tai vạ.Ở trên muố n dùng võ lựcđàn áp như ng rố t cuộ c bị đạibạ i, gây vạ chođấ t nướ c.') ON CONFLICT (hexagram_id, line_number) DO UPDATE SET meaning_static = EXCLUDED.meaning_static, meaning_active = EXCLUDED.meaning_active;
