INSERT INTO lines (hexagram_id, line_number, relation, meaning_static, meaning_active) VALUES (57, 1, '', 'i mà theo nhau thì sẽ làm nên cuộ c thị nh. Chung cùngvớ i ngườ i ta mà sứcđề u nhau thì cố t hạ mìnhđể tìm nhau. Ở thì kỵlữ , lạiở vào dướ i thấ p,ấ y là ngườ i nhu nhượ c. Người có bụ ng dạhẹ p hòi dễ làm chuyệ n bỉ ổ i,đưađế n rướ c nhụcvậ y.', 'i mà theo nhau thì sẽ làm nên cuộ c thị nh. Chung cùngvớ i ngườ i ta mà sứcđề u nhau thì cố t hạ mìnhđể tìm nhau. Ở thì kỵlữ , lạiở vào dướ i thấ p,ấ y là ngườ i nhu nhượ c. Người có bụ ng dạhẹ p hòi dễ làm chuyệ n bỉ ổ i,đưađế n rướ c nhụcvậ y.') ON CONFLICT (hexagram_id, line_number) DO UPDATE SET meaning_static = EXCLUDED.meaning_static, meaning_active = EXCLUDED.meaning_active;
INSERT INTO lines (hexagram_id, line_number, relation, meaning_static, meaning_active) VALUES (57, 2, '', 'Tài củ a kẻ ứ ng vớ i nóđã khôngđủnhờ thì không làm nên cuộ c thị nh. Kẻ có tài mà gặ p phả i vua nhu nhượ c, u ám thìdễbịngờvự c mà ghét bỏ. Mề m thuậ n thì mọ i ngườ i cùng vớ i,đầ y tớcũ ng hế t lòng trung tín vớ i mình. Nhà trọ là nơ i lữ hành yênở ; tiề n củ a là vậ t lữ hành trông cậ y;đầ y tớ là kẻlữ hành nươ ng nhờ.', 'Tài củ a kẻ ứ ng vớ i nóđã khôngđủnhờ thì không làm nên cuộ c thị nh. Kẻ có tài mà gặ p phả i vua nhu nhượ c, u ám thìdễbịngờvự c mà ghét bỏ. Mề m thuậ n thì mọ i ngườ i cùng vớ i,đầ y tớcũ ng hế t lòng trung tín vớ i mình. Nhà trọ là nơ i lữ hành yênở ; tiề n củ a là vậ t lữ hành trông cậ y;đầ y tớ là kẻlữ hành nươ ng nhờ.') ON CONFLICT (hexagram_id, line_number) DO UPDATE SET meaning_static = EXCLUDED.meaning_static, meaning_active = EXCLUDED.meaning_active;
INSERT INTO lines (hexagram_id, line_number, relation, meaning_static, meaning_active) VALUES (57, 3, '', 'Cánh tay phả i là cái ngườ i ta hay dùng, nó bị gãy rồ i thì còn làm gìđượ c nữ a. Tự cao thì không thuậ n vớ i ngườ i trên. Họ đố t cháy chỗ trọ làmấ t chỗ yên. Quá cứ ng thì tàn bạ o vớ i kẻdướ i tứ c làm mất lòng họ.', 'Cánh tay phả i là cái ngườ i ta hay dùng, nó bị gãy rồ i thì còn làm gìđượ c nữ a. Tự cao thì không thuậ n vớ i ngườ i trên. Họ đố t cháy chỗ trọ làmấ t chỗ yên. Quá cứ ng thì tàn bạ o vớ i kẻdướ i tứ c làm mất lòng họ.') ON CONFLICT (hexagram_id, line_number) DO UPDATE SET meaning_static = EXCLUDED.meaning_static, meaning_active = EXCLUDED.meaning_active;
INSERT INTO lines (hexagram_id, line_number, relation, meaning_static, meaning_active) VALUES (57, 4, '', 'ngôi cao màđượ c ngườ i hiề n tài giúp thì tố t lắ m. Nếu không trung chính mà gặ p phả i vua nhu nhượ c thì nên xuố ng. Khôngđượ c lòng ngườ i trên mà chỉ đượ c lòng kẻdướ i thì không thể trổhế t tài mình.', 'ngôi cao màđượ c ngườ i hiề n tài giúp thì tố t lắ m. Nếu không trung chính mà gặ p phả i vua nhu nhượ c thì nên xuố ng. Khôngđượ c lòng ngườ i trên mà chỉ đượ c lòng kẻdướ i thì không thể trổhế t tài mình.') ON CONFLICT (hexagram_id, line_number) DO UPDATE SET meaning_static = EXCLUDED.meaning_static, meaning_active = EXCLUDED.meaning_active;
INSERT INTO lines (hexagram_id, line_number, relation, meaning_static, meaning_active) VALUES (57, 5, '', 'Vua tuy ít tài như ng biế t gầ n bậ c hiề n tài thì vẫ n có thể làm phúc cho thiên hạ. Ông vua không nên có lữ hành vì nhưvậ y là mấ t ngôi. Vua cóđứ c thì lố i kéođượ c ngườ i chung quanh.', 'Vua tuy ít tài như ng biế t gầ n bậ c hiề n tài thì vẫ n có thể làm phúc cho thiên hạ. Ông vua không nên có lữ hành vì nhưvậ y là mấ t ngôi. Vua cóđứ c thì lố i kéođượ c ngườ i chung quanh.') ON CONFLICT (hexagram_id, line_number) DO UPDATE SET meaning_static = EXCLUDED.meaning_static, meaning_active = EXCLUDED.meaning_active;
INSERT INTO lines (hexagram_id, line_number, relation, meaning_static, meaning_active) VALUES (57, 6, '', 'mình tuyệ t vớ i ngườ i ta thì còn cùng vớ i, gầ n vớ i.Ở ngôi cao mà bị đơnđộ c. Nhún mề m ôn hòa mớ i giữ đượ c thân mình. Nế u quá cứ ng tự cao thì sẽmấ t chỗ yên.', 'mình tuyệ t vớ i ngườ i ta thì còn cùng vớ i, gầ n vớ i.Ở ngôi cao mà bị đơnđộ c. Nhún mề m ôn hòa mớ i giữ đượ c thân mình. Nế u quá cứ ng tự cao thì sẽmấ t chỗ yên.') ON CONFLICT (hexagram_id, line_number) DO UPDATE SET meaning_static = EXCLUDED.meaning_static, meaning_active = EXCLUDED.meaning_active;
