INSERT INTO hexagrams (id, name, palace, vietnamese_meaning, overall_meaning, career_meaning, love_meaning, wealth_meaning, health_meaning) VALUES (60, 'Thiên Lôi Vô Vọng', 'Tốn', 'Thiên Lôi Vô Vọng', 'Không vọng động, làm việc đúng bổn phận, đề phòng tai họa bất ngờ.', 'Không vọng động, làm việc đúng bổn phận, đề phòng tai họa bất ngờ.', 'Không vọng động, làm việc đúng bổn phận, đề phòng tai họa bất ngờ.', 'Không vọng động, làm việc đúng bổn phận, đề phòng tai họa bất ngờ.', 'Không vọng động, làm việc đúng bổn phận, đề phòng tai họa bất ngờ.') ON CONFLICT (id) DO UPDATE SET overall_meaning = EXCLUDED.overall_meaning;
INSERT INTO lines (hexagram_id, line_number, relation, meaning_static, meaning_active) VALUES (60, 1, '', 'Có ít khảnă ng mà không cóứ ng việ n thì chư a thể tiếnđượ c. Nạnđã giả i rồ i thì nên yên tỉ nh nghỉngơ i.', 'Có ít khảnă ng mà không cóứ ng việ n thì chư a thể tiếnđượ c. Nạnđã giả i rồ i thì nên yên tỉ nh nghỉngơ i.') ON CONFLICT (hexagram_id, line_number) DO UPDATE SET meaning_static = EXCLUDED.meaning_static, meaning_active = EXCLUDED.meaning_active;
INSERT INTO lines (hexagram_id, line_number, relation, meaning_static, meaning_active) VALUES (60, 2, '', 'Tuy gặ p khó khă n như ng chí muố n giúp ngườ i vượ t qua khó khă n nên về sau không bịlầ m lỗ i. Vua tin dùng kẻ gian tà thì ngườ i quân tử không làm gìđượ c. Trừbỏkẻ tà ác khiếnđạ o trung chính có thể thự c hànhđượ c.', 'Tuy gặ p khó khă n như ng chí muố n giúp ngườ i vượ t qua khó khă n nên về sau không bịlầ m lỗ i. Vua tin dùng kẻ gian tà thì ngườ i quân tử không làm gìđượ c. Trừbỏkẻ tà ác khiếnđạ o trung chính có thể thự c hànhđượ c.') ON CONFLICT (hexagram_id, line_number) DO UPDATE SET meaning_static = EXCLUDED.meaning_static, meaning_active = EXCLUDED.meaning_active;
INSERT INTO lines (hexagram_id, line_number, relation, meaning_static, meaning_active) VALUES (60, 3, '', 'p lúc khó khă n màđượ c lòng kẻdướ i thì có thểcầu đượ c yênổ n. Tài hèn thì không nên làm việ c lớ n.Đứ c không xứ ng vớiđồ dùng, thì giặ c cướpđế n là do mình mờ i nóđế n.', 'p lúc khó khă n màđượ c lòng kẻdướ i thì có thểcầu đượ c yênổ n. Tài hèn thì không nên làm việ c lớ n.Đứ c không xứ ng vớiđồ dùng, thì giặ c cướpđế n là do mình mờ i nóđế n.') ON CONFLICT (hexagram_id, line_number) DO UPDATE SET meaning_static = EXCLUDED.meaning_static, meaning_active = EXCLUDED.meaning_active;
INSERT INTO lines (hexagram_id, line_number, relation, meaning_static, meaning_active) VALUES (60, 4, '', 'Biế t liên hợ p vớ i mọ i ngườ i làđạ o xử lý lúc khó khă n. Ở ngôi trên thì không nên gầ n gũ i kẻ tiể u nhân.Đượ c nhưvậy thì quân tử tìmđế n.', 'Biế t liên hợ p vớ i mọ i ngườ i làđạ o xử lý lúc khó khă n. Ở ngôi trên thì không nên gầ n gũ i kẻ tiể u nhân.Đượ c nhưvậy thì quân tử tìmđế n.') ON CONFLICT (hexagram_id, line_number) DO UPDATE SET meaning_static = EXCLUDED.meaning_static, meaning_active = EXCLUDED.meaning_active;
INSERT INTO lines (hexagram_id, line_number, relation, meaning_static, meaning_active) VALUES (60, 5, '', 'Trên dướiđề u trung chính mà không v ượ t quađượ c khó khă n là vì tài chưa đủ . Nên cầ n ngườ i giúp. Kẻ tiể u nhân lui xuố ng thìđấ ng quân tử tiế n lên.', 'Trên dướiđề u trung chính mà không v ượ t quađượ c khó khă n là vì tài chưa đủ . Nên cầ n ngườ i giúp. Kẻ tiể u nhân lui xuố ng thìđấ ng quân tử tiế n lên.') ON CONFLICT (hexagram_id, line_number) DO UPDATE SET meaning_static = EXCLUDED.meaning_static, meaning_active = EXCLUDED.meaning_active;
INSERT INTO lines (hexagram_id, line_number, relation, meaning_static, meaning_active) VALUES (60, 6, '', 'Trong lúc khó khă n nhiề u mà cóđứ c nên có ngườ i giúp màvượ t khóđượ c. Kẻ tiể u nhân là gố c sinh nạ n, cho nên sau khi giả i nạ n nên nghĩ việ c trừkẻxấ u. Nế u không trừ đượ c làđiềuđáng phả i lo sợ.', 'Trong lúc khó khă n nhiề u mà cóđứ c nên có ngườ i giúp màvượ t khóđượ c. Kẻ tiể u nhân là gố c sinh nạ n, cho nên sau khi giả i nạ n nên nghĩ việ c trừkẻxấ u. Nế u không trừ đượ c làđiềuđáng phả i lo sợ.') ON CONFLICT (hexagram_id, line_number) DO UPDATE SET meaning_static = EXCLUDED.meaning_static, meaning_active = EXCLUDED.meaning_active;
INSERT INTO hexagrams (id, name, palace, vietnamese_meaning, overall_meaning, career_meaning, love_meaning, wealth_meaning, health_meaning) VALUES (61, 'Thiên Hỏa Đồng Nhân', 'Chưa rõ', 'Thiên Hỏa Đồng Nhân', 'Đồng lòng, cùng chung chí hướng, hợp tác mở mang đại nghiệp.', 'Đồng lòng, cùng chung chí hướng, hợp tác mở mang đại nghiệp.', 'Đồng lòng, cùng chung chí hướng, hợp tác mở mang đại nghiệp.', 'Đồng lòng, cùng chung chí hướng, hợp tác mở mang đại nghiệp.', 'Đồng lòng, cùng chung chí hướng, hợp tác mở mang đại nghiệp.') ON CONFLICT (id) DO UPDATE SET overall_meaning = EXCLUDED.overall_meaning;
INSERT INTO lines (hexagram_id, line_number, relation, meaning_static, meaning_active) VALUES (61, 1, '', 'Nhún nhườ ng mà vượ t qua các chỗ hiể m. Lợ i vềsự sang sông lớ n. Kẻ tiể u nhânđượ c ngườ i trên yêu thươ ng nên vui mừ ng quáđỗ i. Nông nổiắ t bị hung.', 'Nhún nhườ ng mà vượ t qua các chỗ hiể m. Lợ i vềsự sang sông lớ n. Kẻ tiể u nhânđượ c ngườ i trên yêu thươ ng nên vui mừ ng quáđỗ i. Nông nổiắ t bị hung.') ON CONFLICT (hexagram_id, line_number) DO UPDATE SET meaning_static = EXCLUDED.meaning_static, meaning_active = EXCLUDED.meaning_active;
INSERT INTO lines (hexagram_id, line_number, relation, meaning_static, meaning_active) VALUES (61, 2, '', 'm thuậ n trung chính, vì sự nhún nhườ ng mà có tiếngtă m. Đươ ng lúc vui mà biế t giữ đạ o trung chính. Nếu đắmđuố i về sự vui thì hóa ra lo.', 'm thuậ n trung chính, vì sự nhún nhườ ng mà có tiếngtă m. Đươ ng lúc vui mà biế t giữ đạ o trung chính. Nếu đắmđuố i về sự vui thì hóa ra lo.') ON CONFLICT (hexagram_id, line_number) DO UPDATE SET meaning_static = EXCLUDED.meaning_static, meaning_active = EXCLUDED.meaning_active;
INSERT INTO lines (hexagram_id, line_number, relation, meaning_static, meaning_active) VALUES (61, 3, '', 'Có công lao mà biế t nhún nhườ ng, lạ i càng làm cho ng ười ta thấ y khó, cho nên sau chót vẫn đắ c thành. Các việcđề u nên hố i lạ i cho mau, nế u không sẽ có sự ă n nă n.', 'Có công lao mà biế t nhún nhườ ng, lạ i càng làm cho ng ười ta thấ y khó, cho nên sau chót vẫn đắ c thành. Các việcđề u nên hố i lạ i cho mau, nế u không sẽ có sự ă n nă n.') ON CONFLICT (hexagram_id, line_number) DO UPDATE SET meaning_static = EXCLUDED.meaning_static, meaning_active = EXCLUDED.meaning_active;
INSERT INTO lines (hexagram_id, line_number, relation, meaning_static, meaning_active) VALUES (61, 4, '', 'Có công lao,đượ c ngườ i trên dùng, dân chúng tôn mà vẫn khiêm tốnđểnhườ ng cho ngườ i khác có công lao thì tố t. Ở vào ngôiđạ i thầ n, vâng thờ vua nhu nhượ c, kẻdướ i không giúp, cho nên phả i ngờ . Chỉ nên hế t lòng thành tín thì bè bạ n tụ họ p.', 'Có công lao,đượ c ngườ i trên dùng, dân chúng tôn mà vẫn khiêm tốnđểnhườ ng cho ngườ i khác có công lao thì tố t. Ở vào ngôiđạ i thầ n, vâng thờ vua nhu nhượ c, kẻdướ i không giúp, cho nên phả i ngờ . Chỉ nên hế t lòng thành tín thì bè bạ n tụ họ p.') ON CONFLICT (hexagram_id, line_number) DO UPDATE SET meaning_static = EXCLUDED.meaning_static, meaning_active = EXCLUDED.meaning_active;
INSERT INTO lines (hexagram_id, line_number, relation, meaning_static, meaning_active) VALUES (61, 5, '', 'Nên dùng uyđố i vớ i ngườ i nào chư a phụ c mình, không phả i chỉ biế t nhu khiêm. Ông vua nhu nhượ c bị đè nén vớ i bề tôi chuyên quyề n. Cưỡi lên kẻcứ ng và bịkẻcứ ng bứ c như ng chư a bịchế t.', 'Nên dùng uyđố i vớ i ngườ i nào chư a phụ c mình, không phả i chỉ biế t nhu khiêm. Ông vua nhu nhượ c bị đè nén vớ i bề tôi chuyên quyề n. Cưỡi lên kẻcứ ng và bịkẻcứ ng bứ c như ng chư a bịchế t.') ON CONFLICT (hexagram_id, line_number) DO UPDATE SET meaning_static = EXCLUDED.meaning_static, meaning_active = EXCLUDED.meaning_active;
INSERT INTO lines (hexagram_id, line_number, relation, meaning_static, meaning_active) VALUES (61, 6, '', 'Khiêm nhuđế n cùng cựcđượ c nhiề u ngườ i theo mình, có thểlấ y sứ c mạ nh ra quân mà trừnhữ ng kẻchố ng lạ i mình.Như ng vì tài kém sứ c yế u, nên cũ ng chỉ trị đượ c nhữ ng kẻ trongấ p mình mà thôi. Chư a thỏ a chíđượ c. Tố i tă m vềsự vui chođế n cùng chót, vạlỗ i sắ p sử a kéođế n, phả i nên thayđổ i cho mau. Sự hôn mêđã thành, nế u biế t biếnđổ i, thì có thể không lỗ i.', 'Khiêm nhuđế n cùng cựcđượ c nhiề u ngườ i theo mình, có thểlấ y sứ c mạ nh ra quân mà trừnhữ ng kẻchố ng lạ i mình.Như ng vì tài kém sứ c yế u, nên cũ ng chỉ trị đượ c nhữ ng kẻ trongấ p mình mà thôi. Chư a thỏ a chíđượ c. Tố i tă m vềsự vui chođế n cùng chót, vạlỗ i sắ p sử a kéođế n, phả i nên thayđổ i cho mau. Sự hôn mêđã thành, nế u biế t biếnđổ i, thì có thể không lỗ i.') ON CONFLICT (hexagram_id, line_number) DO UPDATE SET meaning_static = EXCLUDED.meaning_static, meaning_active = EXCLUDED.meaning_active;
