INSERT INTO hexagrams (id, name, palace, vietnamese_meaning, overall_meaning, career_meaning, love_meaning, wealth_meaning, health_meaning) VALUES (63, 'Bát Thuần Càn', 'Càn', 'Bát Thuần Càn', 'Thuần Càn: Tượng trưng cho Trời, sự cương kiện, sáng tạo vô hạn, mọi sự hanh thông tốt đẹp.', 'Thuần Càn: Tượng trưng cho Trời, sự cương kiện, sáng tạo vô hạn, mọi sự hanh thông tốt đẹp.', 'Thuần Càn: Tượng trưng cho Trời, sự cương kiện, sáng tạo vô hạn, mọi sự hanh thông tốt đẹp.', 'Thuần Càn: Tượng trưng cho Trời, sự cương kiện, sáng tạo vô hạn, mọi sự hanh thông tốt đẹp.', 'Thuần Càn: Tượng trưng cho Trời, sự cương kiện, sáng tạo vô hạn, mọi sự hanh thông tốt đẹp.') ON CONFLICT (id) DO UPDATE SET overall_meaning = EXCLUDED.overall_meaning;
INSERT INTO lines (hexagram_id, line_number, relation, meaning_static, meaning_active) VALUES (63, 1, '', '(Rồ ng lặ n chớ dùng)', 'Quân tửchư a gặ p thờ i thì nênẩn thân tíchđứ c, không nên cầ u danh lợ i.') ON CONFLICT (hexagram_id, line_number) DO UPDATE SET meaning_static = EXCLUDED.meaning_static, meaning_active = EXCLUDED.meaning_active;
INSERT INTO lines (hexagram_id, line_number, relation, meaning_static, meaning_active) VALUES (63, 2, '', '(Rồ ng hiệ n ra ruộ ng, ra mắtđạ i nhân thì có lợ i)', 'Gặ p thờ i,đ em tài lự c giúp chođờ i .') ON CONFLICT (hexagram_id, line_number) DO UPDATE SET meaning_static = EXCLUDED.meaning_static, meaning_active = EXCLUDED.meaning_active;
INSERT INTO lines (hexagram_id, line_number, relation, meaning_static, meaning_active) VALUES (63, 3, '', '(Ngườ i quân tửtố i ngày hă ng hái tựcườ ng, gặ p nguycũ ng khôngđế n nỗ i tộ i lỗ i.', '(Ngườ i quân tửtố i ngày hă ng hái tựcườ ng, gặ p nguycũ ng khôngđế n nỗ i tộ i lỗ i.') ON CONFLICT (hexagram_id, line_number) DO UPDATE SET meaning_static = EXCLUDED.meaning_static, meaning_active = EXCLUDED.meaning_active;
INSERT INTO lines (hexagram_id, line_number, relation, meaning_static, meaning_active) VALUES (63, 4, '', '(Như con rồ ng có khi bay bổ ng, có khi nằ m trong vự c)', 'Phả i thậ n trọ ng xem xét thờ i cơ.') ON CONFLICT (hexagram_id, line_number) DO UPDATE SET meaning_static = EXCLUDED.meaning_static, meaning_active = EXCLUDED.meaning_active;
INSERT INTO lines (hexagram_id, line_number, relation, meaning_static, meaning_active) VALUES (63, 5, '', '(Rồ ng bay lên trờ i, ra mắ t kẻlớ n thì có lợ i)', 'Hào tố t nhấ t. Tuy làđạ o làm tôi như ng là ngôi kẻ làm vua. Giữmứ c trung chính màởdướ i thì rấ t tố t.') ON CONFLICT (hexagram_id, line_number) DO UPDATE SET meaning_static = EXCLUDED.meaning_static, meaning_active = EXCLUDED.meaning_active;
INSERT INTO lines (hexagram_id, line_number, relation, meaning_static, meaning_active) VALUES (63, 6, '', '(Rồ ng lên cao quá có hố i hậ n)', 'Không nên hoạt độ ng gì cả,sớ m rút luiđể giữ việ c an toàn và danh dự.') ON CONFLICT (hexagram_id, line_number) DO UPDATE SET meaning_static = EXCLUDED.meaning_static, meaning_active = EXCLUDED.meaning_active;
